import { createContext, useContext, useState, useCallback } from 'react';

const AuthContext = createContext(null);
const VALID_ROLES = new Set(['ADMIN', 'DONOR', 'ORGANIZATION']);

function readStoredUser() {
  try {
    const stored = localStorage.getItem('donation_user');
    const token = localStorage.getItem('donation_token');
    if (!stored || !token) return null;

    const parsed = JSON.parse(stored);
    if (!parsed || typeof parsed !== 'object') return null;
    if (!VALID_ROLES.has(parsed.role)) return null;
    if (typeof parsed.name !== 'string' || typeof parsed.email !== 'string') return null;

    return { ...parsed, token };
  } catch {
    return null;
  }
}

function clearStoredAuth() {
  localStorage.removeItem('donation_user');
  localStorage.removeItem('donation_token');
}

export function AuthProvider({ children }) {
  const [user, setUser] = useState(() => {
    const storedUser = readStoredUser();
    if (!storedUser) clearStoredAuth();
    return storedUser;
  });

  const login = useCallback((userData) => {
    const normalizedUser = { ...userData, token: userData.token };
    localStorage.setItem('donation_user', JSON.stringify(normalizedUser));
    localStorage.setItem('donation_token', userData.token);
    setUser(normalizedUser);
  }, []);

  const logout = useCallback(() => {
    clearStoredAuth();
    setUser(null);
  }, []);

  const isAuthenticated = Boolean(user?.token && VALID_ROLES.has(user?.role));

  return (
    <AuthContext.Provider value={{ user, login, logout, isAuthenticated }}>
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error('useAuth must be used within AuthProvider');
  return ctx;
}
