import axios from 'axios';

const api = axios.create({
  baseURL: '/api',
  headers: { 'Content-Type': 'application/json' },
});

function clearStoredAuth() {
  localStorage.removeItem('donation_user');
  localStorage.removeItem('donation_token');
}

// Inject JWT token from localStorage on every request
api.interceptors.request.use((config) => {
  const token = localStorage.getItem('donation_token');
  if (token) {
    config.headers.Authorization = `Bearer ${token}`;
  }
  return config;
});

// Redirect to login on 401
api.interceptors.response.use(
  (response) => response,
  (error) => {
    const originalRequest = error.config;
    const token = localStorage.getItem('donation_token');
    const isUnauthorized = error.response?.status === 401;
    const isLoginRequest = String(originalRequest?.url || '').includes('/auth/login');

    if (isUnauthorized && token && originalRequest && !originalRequest._retry && !isLoginRequest) {
      originalRequest._retry = true;
      originalRequest.headers = {
        ...(originalRequest.headers || {}),
        Authorization: `Bearer ${token}`,
      };
      return api(originalRequest);
    }

    if (isUnauthorized && !isLoginRequest) {
      clearStoredAuth();
      if (window.location.pathname !== '/login') {
        window.location.assign('/login');
      }
    }
    return Promise.reject(error);
  }
);

// ── Auth ──────────────────────────────────────────────────
export const registerUser = (data)  => api.post('/auth/register', data);
export const loginUser    = (data)  => api.post('/auth/login', data);

// ── Food ──────────────────────────────────────────────────
export const postFood      = (data)     => api.post('/food', data);
export const getAllFood    = ()         => api.get('/food/all');
export const getRankedFood = ()         => api.get('/food/ranked');
export const getMyFood     = ()         => api.get('/food/my');
export const acceptFood    = (foodId)   => api.post(`/food/accept/${foodId}`);
export const rejectFood    = (foodId)   => api.post(`/food/reject/${foodId}`);
export const updateFoodStatus = (foodId, status) => api.put(`/food/status/${foodId}?status=${status}`);
export const deleteFood    = (foodId)   => api.delete(`/food/${foodId}`);
export const getBestMatch  = (foodId)   => api.get(`/food/match/${foodId}`);
export const selectDeliveryMode = (foodId, mode) => api.post('/food/select-delivery', { foodId, mode });

// ── Delivery ──────────────────────────────────────────────
export const createDelivery   = (foodId)             => api.post(`/delivery/create/${foodId}`);
export const updateDelivery   = (deliveryId, data)   => api.patch(`/delivery/update/${deliveryId}`, data);
export const getDelivery      = (foodId)             => api.get(`/delivery/${foodId}`);

// ── NGO ───────────────────────────────────────────────────
export const getAvailableNgos = ()            => api.get('/ngo/available');
export const assignNgoDelivery = (foodId, ngoId) => api.post(`/ngo/assign/${foodId}?ngoId=${ngoId}`);

// ── Chat ──────────────────────────────────────────────────
export const sendMessage = (foodId, data) => api.post('/chat/send', { foodId, ...data });
export const getMessages = (foodId)       => api.get(`/chat/${foodId}`);

// ── Admin ─────────────────────────────────────────────────
export const getOrganizations   = ()       => api.get('/admin/organizations');
export const verifyOrganization = (userId) => api.patch(`/admin/verify/${userId}`);
export const getAdminStats      = ()       => api.get('/admin/stats');

export default api;
