import React from 'react';

class RouteErrorBoundary extends React.Component {
  constructor(props) {
    super(props);
    this.state = { hasError: false };
  }

  static getDerivedStateFromError() {
    return { hasError: true };
  }

  componentDidCatch(error) {
    console.error('Route render failed:', error);
  }

  render() {
    if (this.state.hasError) {
      return (
        <div className="glass-card p-10 text-center border border-red-500/20 bg-red-500/5">
          <h2 className="text-2xl font-bold text-white mb-3">Dashboard Failed To Load</h2>
          <p className="text-slate-300 mb-4">
            The page hit a runtime error. Refresh once, and if it happens again sign out and back in.
          </p>
          <button
            type="button"
            onClick={() => window.location.reload()}
            className="btn-primary px-5 py-2"
          >
            Refresh
          </button>
        </div>
      );
    }

    return this.props.children;
  }
}

export default RouteErrorBoundary;
