import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';

export default function Navbar() {
  const { user, logout, isAuthenticated } = useAuth();
  const navigate = useNavigate();
  const isGuest = !isAuthenticated || !user;

  const handleLogout = () => {
    logout();
    toast.success('Logged out successfully');
    navigate('/login');
  };

  const navLinks = {
    ADMIN: [
      { path: '/', label: 'Home' },
      { path: '/dashboard', label: 'Dashboard' },
    ],
    DONOR: [
      { path: '/', label: 'Home' },
      { path: '/dashboard', label: 'My Donations' },
      { path: '/post-food', label: 'Post Food' },
    ],
    ORGANIZATION: [
      { path: '/', label: 'Home' },
      { path: '/dashboard', label: 'Organization Hub' },
    ],
  };

  const links = !isGuest ? (navLinks[user.role] || []) : [];
  const brandTarget = isGuest ? '/' : '/dashboard';

  return (
    <nav className="sticky top-0 z-50 mx-4 mt-6">
      <div className="glass-card px-4 sm:px-6 py-3 border border-white/5 shadow-2xl backdrop-blur-3xl">
        <div className="flex items-center justify-between gap-6">
          <Link to={brandTarget} className="flex items-center gap-3 group">
            <div className="w-10 h-10 rounded-2xl bg-brand-500/10 border border-brand-500/20 text-brand-400 flex items-center justify-center font-black tracking-tight group-hover:bg-brand-500/20 transition-colors">
              FS
            </div>
            <span className="text-lg sm:text-xl font-black text-white tracking-tight">FoodShare</span>
          </Link>
        
          <div className="flex items-center gap-8">
            <div className="hidden md:flex items-center gap-6">
              {links.map((link) => (
                <Link
                  key={link.path}
                  to={link.path}
                  className="text-xs font-black text-slate-400 hover:text-brand-400 transition-colors uppercase tracking-[0.22em]"
                >
                  {link.label}
                </Link>
              ))}
            </div>

            {!isGuest ? (
              <div className="flex items-center gap-4 border-l border-white/10 pl-8">
                <div className="hidden sm:flex flex-col items-end">
                  <span className="text-xs font-bold text-white tracking-tight">{user.name}</span>
                  <span className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">{user.role}</span>
                </div>
                <button
                  onClick={handleLogout}
                  className="px-4 py-2 rounded-xl bg-white/5 hover:bg-red-500/20 hover:text-red-300 transition-all border border-white/10 text-xs font-black uppercase tracking-widest"
                  title="Log out"
                >
                  Logout
                </button>
              </div>
            ) : (
              <div className="flex items-center gap-3">
                <Link
                  to="/login"
                  className="px-4 py-2 rounded-xl bg-white/5 hover:bg-white/10 transition-all border border-white/10 text-xs font-black uppercase tracking-widest text-slate-200"
                >
                  Sign In
                </Link>
                <Link
                  to="/register"
                  className="btn-primary px-5 py-2 text-xs font-black uppercase tracking-widest"
                >
                  Get Started
                </Link>
              </div>
            )}
          </div>
        </div>
      </div>
    </nav>
  );
}
