import { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { loginUser } from '../services/api';
import { useAuth } from '../context/AuthContext';
import Loader from '../components/Loader';
import toast from 'react-hot-toast';

export default function Login() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const { data } = await loginUser({ email, password });
      login(data, data.token);
      toast.success(`Welcome back, ${data.name}!`);
      navigate('/dashboard');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Login failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-[80vh] flex flex-col items-center justify-center animate-fade-in">
      <div className="w-full max-w-md">
        <div className="text-center mb-10">
          <div className="inline-flex items-center justify-center w-16 h-16 rounded-3xl bg-brand-500/10 border border-brand-500/20 mb-4">
            <span className="text-brand-400 font-black tracking-tight">FS</span>
          </div>
          <h1 className="text-4xl font-black text-white tracking-tight">FoodShare</h1>
          <p className="text-slate-400 mt-2">Sign in to coordinate food donations with verified organizations.</p>
        </div>

        <div className="glass-card p-10 border-white/10">
          <form onSubmit={handleSubmit} className="space-y-6">
            <div>
              <label className="block text-xs font-bold text-white mb-2 uppercase tracking-widest opacity-60">Email Address</label>
              <input 
                type="email" 
                value={email} 
                onChange={(e) => setEmail(e.target.value)} 
                className="input-field" 
                placeholder="name@example.com"
                required 
              />
            </div>
            <div>
              <label className="block text-xs font-bold text-white mb-2 uppercase tracking-widest opacity-60">Password</label>
              <input 
                type="password" 
                value={password} 
                onChange={(e) => setPassword(e.target.value)} 
                className="input-field" 
                placeholder="••••••••"
                required 
              />
            </div>
            
            <button 
              type="submit" 
              disabled={loading} 
              className="btn-primary w-full py-3 font-bold text-lg shadow-lg shadow-brand-500/30 flex items-center justify-center gap-2"
            >
              {loading ? <Loader size="sm" color="white" /> : 'Log In'}
            </button>
          </form>

          <p className="mt-8 text-center text-sm text-slate-500">
            New to the platform?{' '}
            <Link to="/register" className="text-brand-400 font-bold hover:underline">Create an account</Link>
          </p>
        </div>

        {/* Admin Creds Hint */}
        <div className="mt-10 p-4 bg-white/5 border border-white/5 rounded-2xl text-center">
            <p className="text-[10px] text-slate-500 uppercase tracking-widest font-bold mb-1">Demo Admin Credentials</p>
            <p className="text-xs text-slate-400">admin@fooddonate.com / admin123</p>
        </div>
      </div>
    </div>
  );
}
