import { useCallback, useEffect, useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import ConfirmModal from '../components/ConfirmModal';
import Loader from '../components/Loader';
import { deleteFood, getMyFood } from '../services/api';
import { formatDateTime, formatEnumLabel, safeText } from '../utils/workflow';

function getStatusClasses(status) {
  switch (String(status || '').toUpperCase()) {
    case 'DELIVERED':
      return 'border-emerald-400/20 bg-emerald-400/10 text-emerald-200';
    case 'PICKUP_STARTED':
      return 'border-sky-400/20 bg-sky-400/10 text-sky-200';
    case 'ACCEPTED':
      return 'border-amber-400/20 bg-amber-400/10 text-amber-200';
    default:
      return 'border-slate-700/70 bg-white/[0.05] text-slate-200';
  }
}

function getCategoryClasses(category) {
  switch (String(category || '').toUpperCase()) {
    case 'VEG':
      return 'border-emerald-400/20 bg-emerald-400/10 text-emerald-200';
    case 'NON_VEG':
      return 'border-rose-400/20 bg-rose-400/10 text-rose-200';
    case 'SPICY':
      return 'border-orange-400/20 bg-orange-400/10 text-orange-200';
    case 'OTHER':
      return 'border-cyan-400/20 bg-cyan-400/10 text-cyan-100';
    case 'NUTRITIOUS':
      return 'border-yellow-400/20 bg-yellow-400/10 text-yellow-100';
    default:
      return 'border-cyan-400/20 bg-cyan-400/10 text-cyan-100';
  }
}

function StatTile({ label, value }) {
  return (
    <div className="rounded-[24px] border border-slate-800/80 bg-white/[0.045] px-5 py-4 shadow-[inset_0_1px_0_rgba(255,255,255,0.03)]">
      <p className="text-[10px] font-semibold uppercase tracking-[0.28em] text-slate-500">{label}</p>
      <p className="mt-3 text-3xl font-semibold tracking-tight text-white">{value}</p>
    </div>
  );
}

function InfoCell({ label, value }) {
  return (
    <div className="rounded-[22px] border border-slate-800/80 bg-white/[0.035] px-4 py-4">
      <p className="text-[10px] font-semibold uppercase tracking-[0.24em] text-slate-500">{label}</p>
      <p className="mt-2 text-sm font-medium leading-6 text-slate-100">{value}</p>
    </div>
  );
}

function DonationCard({ donation, onOpen, onDelete }) {
  return (
    <div
      role="button"
      tabIndex={0}
      onClick={() => onOpen(donation.id)}
      onKeyDown={(event) => {
        if (event.key === 'Enter' || event.key === ' ') {
          event.preventDefault();
          onOpen(donation.id);
        }
      }}
      className="group w-full cursor-pointer overflow-hidden rounded-[30px] border border-slate-800/80 glass-card text-left transition-all duration-300 hover:-translate-y-1 hover:border-brand-500/20"
    >
      <div className="p-6 sm:p-7">
        <div className="flex flex-col gap-5 lg:flex-row lg:items-start lg:justify-between">
          <div className="space-y-4">
            <div className="flex flex-wrap items-center gap-2">
              <span className={`rounded-full border px-3 py-1 text-[10px] font-semibold uppercase tracking-[0.22em] ${getCategoryClasses(donation.category)}`}>
                {formatEnumLabel(donation.category, 'Donation')}
              </span>
              <span className={`rounded-full border px-3 py-1 text-[10px] font-semibold uppercase tracking-[0.22em] ${getStatusClasses(donation.status)}`}>
                {formatEnumLabel(donation.status, 'Posted')}
              </span>
            </div>

            <div>
              <h2 className="text-[26px] font-semibold tracking-tight text-white">
                {safeText(donation.title, 'Untitled donation')}
              </h2>
              <p className="mt-2 text-[15px] font-medium text-slate-400">
                {safeText(donation.type, 'Food item')} | Qty {safeText(donation.quantity, '0')}
              </p>
            </div>
          </div>

          <div className="flex flex-wrap items-center gap-2">
            {String(donation?.status || '').toUpperCase() === 'POSTED' ? (
              <button
                type="button"
                onClick={(event) => {
                  event.stopPropagation();
                  onDelete(donation.id);
                }}
                className="inline-flex items-center rounded-full border border-rose-500/20 bg-rose-500/10 px-4 py-2 text-[11px] font-semibold uppercase tracking-[0.22em] text-rose-100 transition-colors hover:bg-rose-500/20"
              >
                Delete
              </button>
            ) : null}
          </div>
        </div>

        <div className="mt-6 grid gap-3 sm:grid-cols-3">
          <InfoCell
            label="Recipient"
            value={safeText(donation.acceptedByName, 'Awaiting organization')}
          />
          <InfoCell
            label="Expires"
            value={formatDateTime(donation.expiryTime)}
          />
          <InfoCell
            label="Delivery"
            value={formatEnumLabel(donation.deliveryMode, 'Pending')}
          />
        </div>
      </div>
    </div>
  );
}

export default function DonorDashboardOverview() {
  const navigate = useNavigate();
  const [items, setItems] = useState([]);
  const [loading, setLoading] = useState(true);
  const [dialog, setDialog] = useState(null);
  const [actionBusy, setActionBusy] = useState(false);

  const refreshDonations = useCallback(async () => {
    try {
      const { data } = await getMyFood();
      setItems(Array.isArray(data) ? data : []);
    } catch (err) {
      toast.error(err?.response?.data?.message || 'Failed to refresh donations');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    refreshDonations();
    const interval = setInterval(refreshDonations, 4000);
    return () => clearInterval(interval);
  }, [refreshDonations]);

  const handleDelete = async (id) => {
    try {
      await deleteFood(id);
      await refreshDonations();
      toast.success('Donation deleted');
    } catch (err) {
      toast.error(err?.response?.data?.message || 'Delete failed');
      throw err;
    }
  };

  const stats = useMemo(() => ({
    total: items.length,
    active: items.filter((item) => item?.status !== 'DELIVERED').length,
    pending: items.filter((item) => item?.status === 'POSTED').length,
    delivered: items.filter((item) => item?.status === 'DELIVERED').length,
  }), [items]);

  if (loading) return <Loader size="lg" />;

  return (
    <div className="space-y-8 animate-fade-in">
      <section className="overflow-hidden rounded-[36px] border border-slate-800/80 bg-[radial-gradient(circle_at_top_left,_rgba(16,185,129,0.16),_transparent_34%),radial-gradient(circle_at_bottom_right,_rgba(59,130,246,0.10),_transparent_30%),linear-gradient(180deg,rgba(15,23,42,0.96),rgba(5,11,22,0.98))] p-7 shadow-[0_26px_90px_rgba(3,8,20,0.48)] sm:p-9">
        <div className="flex flex-col gap-8 xl:flex-row xl:items-end xl:justify-between">
          <div className="max-w-2xl">
            <p className="text-[11px] font-semibold uppercase tracking-[0.34em] text-brand-300">My Donations</p>
            <h1 className="mt-4 text-3xl font-semibold tracking-tight text-white sm:text-[42px]">
              Professional control over every donation you have shared.
            </h1>
            <p className="mt-4 text-[15px] leading-7 text-slate-300">
              Review progress, correct mistakes early, and step into delivery only when needed.
            </p>
          </div>

          <div className="grid grid-cols-2 gap-3 sm:grid-cols-4 xl:min-w-[420px]">
            <StatTile label="Total" value={stats.total} />
            <StatTile label="Active" value={stats.active} />
            <StatTile label="Pending" value={stats.pending} />
            <StatTile label="Delivered" value={stats.delivered} />
          </div>
        </div>
      </section>

      {items.length === 0 ? (
        <div className="glass-card rounded-[30px] p-12 text-center">
          <h2 className="text-2xl font-semibold text-white">No donations yet</h2>
          <p className="mt-3 text-sm text-slate-400">Start with your first donation.</p>
          <button type="button" onClick={() => navigate('/post-food')} className="btn-primary mt-6 px-6 py-3">
            Post Food
          </button>
        </div>
      ) : (
        <div className="space-y-5">
          <div className="flex flex-wrap items-center justify-between gap-4">
            <div>
              <h2 className="text-[28px] font-semibold tracking-tight text-white">Donation List</h2>
              <p className="mt-1 text-sm text-slate-400">Review any donation directly from the list, or delete a wrong post before it gets accepted.</p>
            </div>
            <button
              type="button"
              onClick={() => navigate('/post-food')}
              className="rounded-full border border-slate-700/70 bg-white/[0.04] px-5 py-3 text-[11px] font-semibold uppercase tracking-[0.22em] text-slate-200 transition-all hover:border-brand-500/30 hover:text-white"
            >
              New Donation
            </button>
          </div>

          <div className="space-y-4">
            {items.map((item) => (
              <DonationCard
                key={item.id}
                donation={item}
                onOpen={(id) => navigate(`/dashboard/donations/${id}`)}
                onDelete={(id) => setDialog({
                  id,
                  title: 'Delete Donation',
                  message: 'This will permanently remove the posted donation. Use this only when the donation details are wrong.',
                  confirmLabel: 'Delete Donation',
                  tone: 'danger',
                })}
              />
            ))}
          </div>
        </div>
      )}

      <ConfirmModal
        open={Boolean(dialog)}
        title={dialog?.title}
        message={dialog?.message}
        confirmLabel={dialog?.confirmLabel}
        tone={dialog?.tone}
        busy={actionBusy}
        onConfirm={async () => {
          if (!dialog?.id) return;
          setActionBusy(true);
          try {
            await handleDelete(dialog.id);
            setDialog(null);
          } finally {
            setActionBusy(false);
          }
        }}
        onClose={() => {
          if (!actionBusy) setDialog(null);
        }}
      />
    </div>
  );
}

