import { useNavigate } from 'react-router-dom';
import { useRegistration } from '../context/RegistrationContext';

const ROLE_CARDS = [
  {
    role: 'DONOR',
    title: 'Donor',
    subtitle: 'I want to donate food',
    description: 'Fast signup for households, restaurants, and community donors donating surplus food.',
    icon: (
      <svg viewBox="0 0 24 24" className="w-8 h-8" fill="none" stroke="currentColor" strokeWidth="1.8">
        <path d="M12 21c4-3.2 7-6.2 7-10a4 4 0 0 0-7-2.6A4 4 0 0 0 5 11c0 3.8 3 6.8 7 10Z" />
      </svg>
    ),
  },
  {
    role: 'ORGANIZATION',
    title: 'Organization',
    subtitle: 'I want to receive food',
    description: 'Signup for NGOs, shelters, orphanages, and old age homes to receive food donations.',
    icon: (
      <svg viewBox="0 0 24 24" className="w-8 h-8" fill="none" stroke="currentColor" strokeWidth="1.8">
        <path d="M3 21h18" />
        <path d="M5 21V9l7-5 7 5v12" />
        <path d="M9 21v-5h6v5" />
      </svg>
    ),
  },
];

export default function RegisterRoleSelect() {
  const navigate = useNavigate();
  const { setSelectedRole } = useRegistration();

  const chooseRole = (role) => {
    setSelectedRole(role);
    navigate(`/register/${role.toLowerCase()}`);
  };

  return (
    <div className="min-h-[88vh] flex items-center justify-center animate-fade-in py-10">
      <div className="w-full max-w-5xl">
        <div className="text-center mb-12">
          <h1 className="text-5xl font-black text-white tracking-tight">Join FoodShare</h1>
          <p className="text-slate-400 mt-3 text-lg">Choose your role to get started.</p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          {ROLE_CARDS.map((card) => (
            <button
              key={card.role}
              type="button"
              onClick={() => chooseRole(card.role)}
              className="glass-card p-10 text-left border border-white/10 hover:border-brand-500/40 hover:-translate-y-1 hover:shadow-2xl hover:shadow-brand-500/10 transition-all duration-300 group"
            >
              <div className="w-14 h-14 rounded-2xl bg-brand-500/10 text-brand-400 flex items-center justify-center mb-6 group-hover:bg-brand-500/20">
                {card.icon}
              </div>
              <h2 className="text-3xl font-black text-white">{card.title}</h2>
              <p className="text-brand-400 mt-3 font-semibold">{card.subtitle}</p>
              <p className="text-slate-400 mt-4 leading-relaxed">{card.description}</p>
              <div className="mt-8 inline-flex items-center gap-2 text-sm font-bold text-white">
                Continue
                <span className="text-brand-400">-&gt;</span>
              </div>
            </button>
          ))}
        </div>
      </div>
    </div>
  );
}
