import { useEffect, useMemo, useState } from 'react';
import { Link, useNavigate, useParams } from 'react-router-dom';
import toast from 'react-hot-toast';
import { registerUser } from '../services/api';
import { useAuth } from '../context/AuthContext';
import { useRegistration } from '../context/RegistrationContext';
import Loader from '../components/Loader';

const ORG_TYPES = ['OLD_AGE_HOME', 'ORPHANAGE', 'SHELTER_HOME', 'NGO', 'HOSPITAL', 'SCHOOL', 'DISASTER_RELIEF_CENTER', 'ANIMAL_SHELTER', 'CHARITY'];

const strongPassword = (value) =>
  /^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)(?=.*[^A-Za-z\d]).{8,}$/.test(value);

const iconButtonClass = 'absolute right-3 top-[42px] text-xs font-bold text-slate-400 hover:text-white transition-colors';

function FieldError({ message }) {
  if (!message) return null;
  return <p className="text-red-400 text-[10px] mt-1 font-bold">{message}</p>;
}

function PasswordField({ label, name, value, onChange, error, visible, onToggle }) {
  return (
    <div className="relative">
      <label className="block text-xs font-bold text-white mb-2 uppercase tracking-widest opacity-60">{label}</label>
      <input
        name={name}
        type={visible ? 'text' : 'password'}
        value={value}
        onChange={onChange}
        className="input-field pr-16"
        placeholder={label}
      />
      <button type="button" onClick={onToggle} className={iconButtonClass}>
        {visible ? 'Hide' : 'Show'}
      </button>
      <FieldError message={error} />
    </div>
  );
}

function lookupPincode(pinCode, setField, setErrors) {
  if (!/^\d{6}$/.test(pinCode)) return;

  fetch(`https://api.postalpincode.in/pincode/${pinCode}`)
    .then((response) => response.json())
    .then((result) => {
      const office = result?.[0]?.PostOffice?.[0];
      if (!office) return;
      setField('state', office.State || '');
      setField('district', office.District || '');
      setErrors((current) => ({ ...current, state: '', district: '', pinCode: '' }));
    })
    .catch(() => {
      toast.error('Could not auto-fetch state and district for this pincode');
    });
}

export default function RegisterFlow() {
  const { role } = useParams();
  const navigate = useNavigate();
  const { login } = useAuth();
  const {
    setSelectedRole,
    donorDraft,
    setDonorDraft,
    organizationDraft,
    setOrganizationDraft,
    resetRegistration,
  } = useRegistration();

  const normalizedRole = role === 'organization' ? 'ORGANIZATION' : role === 'donor' ? 'DONOR' : null;
  const [errors, setErrors] = useState({});
  const [loading, setLoading] = useState(false);
  const [passwordVisible, setPasswordVisible] = useState(false);
  const [confirmVisible, setConfirmVisible] = useState(false);
  const [documentPreview, setDocumentPreview] = useState('');

  useEffect(() => {
    if (!normalizedRole) {
      navigate('/register', { replace: true });
      return;
    }
    setSelectedRole(normalizedRole);
  }, [navigate, normalizedRole, setSelectedRole]);

  const isOrganization = normalizedRole === 'ORGANIZATION';
  const form = isOrganization ? organizationDraft : donorDraft;
  const setForm = isOrganization ? setOrganizationDraft : setDonorDraft;

  useEffect(() => {
    if (!isOrganization) {
      setDocumentPreview('');
      return;
    }
    if (organizationDraft.documentUrl?.startsWith('data:image')) {
      setDocumentPreview(organizationDraft.documentUrl);
    } else {
      setDocumentPreview('');
    }
  }, [isOrganization, organizationDraft.documentUrl]);

  const setField = (name, value) => {
    setForm((current) => ({ ...current, [name]: value }));
    setErrors((current) => ({ ...current, [name]: '' }));
  };

  const validate = useMemo(() => {
    return (currentForm) => {
      const next = {};
      const requireText = (key, label) => {
        if (!String(currentForm[key] || '').trim()) next[key] = `${label} is required`;
      };

      if (isOrganization) {
        requireText('orgName', 'Organization name');
        requireText('contactPersonName', 'Contact person name');
      } else {
        requireText('name', 'Full name');
      }

      requireText('email', 'Email address');
      if (currentForm.email && !/\S+@\S+\.\S+/.test(currentForm.email)) next.email = 'Invalid email format';

      requireText('password', 'Password');
      if (currentForm.password && !strongPassword(currentForm.password)) {
        next.password = 'Use 8+ chars with upper, lower, number, and symbol';
      }

      requireText('confirmPassword', 'Confirm password');
      if (currentForm.password !== currentForm.confirmPassword) next.confirmPassword = 'Passwords do not match';

      requireText('mobileNumber', 'Mobile number');
      if (currentForm.mobileNumber && !/^\d{10}$/.test(currentForm.mobileNumber)) {
        next.mobileNumber = 'Mobile number must be 10 digits';
      }

      requireText('fullAddress', 'Address');
      requireText('pinCode', 'Pin code');
      if (currentForm.pinCode && !/^\d{6}$/.test(currentForm.pinCode)) next.pinCode = 'Pin code must be 6 digits';
      requireText('state', 'State');
      requireText('district', 'District');
      requireText('location', 'Location');

      if (isOrganization) {
        requireText('orgType', 'Organization type');
        requireText('registrationNumber', 'Registration number');
        if (!currentForm.documentUrl) next.documentUrl = 'Verification document is required';
      }

      return next;
    };
  }, [isOrganization]);

  const handleChange = (e) => {
    const { name, value, type, checked } = e.target;
    const nextValue = type === 'checkbox' ? checked : value;
    setField(name, nextValue);
    if (name === 'pinCode') {
      lookupPincode(nextValue, setField, setErrors);
    }
  };

  const detectLocation = () => {
    if (!navigator.geolocation) {
      toast.error('Browser location is not supported');
      return;
    }

    navigator.geolocation.getCurrentPosition(
      (position) => {
        const coords = `${position.coords.latitude.toFixed(5)},${position.coords.longitude.toFixed(5)}`;
        setField('location', coords);
        toast.success('Location detected');
      },
      () => toast.error('Could not detect your location')
    );
  };

  const handleDocumentChange = (e) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = () => {
      setField('documentUrl', String(reader.result || ''));
      setField('documentName', file.name);
    };
    reader.readAsDataURL(file);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const validationErrors = validate(form);
    if (Object.keys(validationErrors).length) {
      setErrors(validationErrors);
      toast.error('Please fix the highlighted fields');
      return;
    }

    const payload = isOrganization
      ? {
          role: 'ORGANIZATION',
          name: form.contactPersonName,
          orgName: form.orgName,
          contactPersonName: form.contactPersonName,
          email: form.email,
          password: form.password,
          mobileNumber: form.mobileNumber,
          fullAddress: form.fullAddress,
          pinCode: form.pinCode,
          state: form.state,
          district: form.district,
          location: form.location,
          orgType: form.orgType,
          registrationNumber: form.registrationNumber,
          documentUrl: form.documentUrl,
          pickupAvailable: Boolean(form.pickupAvailable),
          deliveryRequired: Boolean(form.deliveryRequired),
        }
      : {
          role: 'DONOR',
          name: form.name,
          email: form.email,
          password: form.password,
          mobileNumber: form.mobileNumber,
          fullAddress: form.fullAddress,
          pinCode: form.pinCode,
          state: form.state,
          district: form.district,
          location: form.location,
        };

    setLoading(true);
    try {
      const { data } = await registerUser(payload);
      if (isOrganization) {
        toast.success('Registration submitted. Your account will be activated after admin verification.', { duration: 5000 });
        resetRegistration();
        navigate('/login');
      } else {
        login(data);
        toast.success(`Welcome to FoodShare, ${data.name}!`);
        resetRegistration();
        navigate('/dashboard');
      }
    } catch (err) {
      toast.error(err.response?.data?.message || 'Registration failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-[92vh] flex items-center justify-center py-10 animate-fade-in">
      <div className="w-full max-w-5xl">
        <div className="text-center mb-10">
          <h1 className="text-5xl font-black text-white tracking-tight">
            {isOrganization ? 'Register Organization' : 'Register Donor'}
          </h1>
          <p className="text-slate-400 mt-3">
            {isOrganization ? 'Complete verification details to receive food donations.' : 'A fast signup to start donating surplus food quickly.'}
          </p>
        </div>

        <div className="glass-card p-8 md:p-10">
          <div className="flex items-center justify-between mb-8">
            <div>
              <p className="text-xs uppercase tracking-[0.3em] text-slate-500 font-black">Role</p>
              <p className="text-white font-bold mt-2">{isOrganization ? 'Organization' : 'Donor'}</p>
            </div>
            <button type="button" onClick={() => navigate('/register')} className="text-sm text-brand-400 font-bold hover:underline">
              Change Role
            </button>
          </div>

          <form onSubmit={handleSubmit} className="space-y-8">
            <section className="space-y-6">
              <div className="flex items-center justify-between">
                <h2 className="text-lg font-black text-white">{isOrganization ? 'Basic Info' : 'Account Info'}</h2>
                <p className="text-[10px] uppercase tracking-[0.25em] text-slate-500">Required fields only</p>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {isOrganization ? (
                  <>
                    <div>
                      <label className="block text-xs font-bold text-white mb-2 uppercase tracking-widest opacity-60">Organization Name</label>
                      <input name="orgName" value={form.orgName} onChange={handleChange} className="input-field" placeholder="Care Foundation" />
                      <FieldError message={errors.orgName} />
                    </div>
                    <div>
                      <label className="block text-xs font-bold text-white mb-2 uppercase tracking-widest opacity-60">Contact Person Name</label>
                      <input name="contactPersonName" value={form.contactPersonName} onChange={handleChange} className="input-field" placeholder="Anita Sharma" />
                      <FieldError message={errors.contactPersonName} />
                    </div>
                  </>
                ) : (
                  <div>
                    <label className="block text-xs font-bold text-white mb-2 uppercase tracking-widest opacity-60">Full Name</label>
                    <input name="name" value={form.name} onChange={handleChange} className="input-field" placeholder="John Doe" />
                    <FieldError message={errors.name} />
                  </div>
                )}

                <div>
                  <label className="block text-xs font-bold text-white mb-2 uppercase tracking-widest opacity-60">Email Address</label>
                  <input name="email" type="email" value={form.email} onChange={handleChange} className="input-field" placeholder="name@example.com" />
                  <FieldError message={errors.email} />
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <PasswordField
                  label="Password"
                  name="password"
                  value={form.password}
                  onChange={handleChange}
                  error={errors.password}
                  visible={passwordVisible}
                  onToggle={() => setPasswordVisible((current) => !current)}
                />
                <PasswordField
                  label="Confirm Password"
                  name="confirmPassword"
                  value={form.confirmPassword}
                  onChange={handleChange}
                  error={errors.confirmPassword}
                  visible={confirmVisible}
                  onToggle={() => setConfirmVisible((current) => !current)}
                />
              </div>
            </section>

            <section className="space-y-6">
              <h2 className="text-lg font-black text-white">{isOrganization ? 'Address & Contact' : 'Contact & Location'}</h2>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label className="block text-xs font-bold text-white mb-2 uppercase tracking-widest opacity-60">Mobile Number</label>
                  <input name="mobileNumber" value={form.mobileNumber} onChange={handleChange} className="input-field" placeholder="9876543210" />
                  <FieldError message={errors.mobileNumber} />
                </div>
                <div>
                  <label className="block text-xs font-bold text-white mb-2 uppercase tracking-widest opacity-60">Pincode</label>
                  <input name="pinCode" value={form.pinCode} onChange={handleChange} className="input-field" placeholder="110001" />
                  <FieldError message={errors.pinCode} />
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label className="block text-xs font-bold text-white mb-2 uppercase tracking-widest opacity-60">State</label>
                  <input name="state" value={form.state} onChange={handleChange} className="input-field" placeholder="Auto-filled from pincode" />
                  <FieldError message={errors.state} />
                </div>
                <div>
                  <label className="block text-xs font-bold text-white mb-2 uppercase tracking-widest opacity-60">District</label>
                  <input name="district" value={form.district} onChange={handleChange} className="input-field" placeholder="Auto-filled from pincode" />
                  <FieldError message={errors.district} />
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label className="block text-xs font-bold text-white mb-2 uppercase tracking-widest opacity-60">
                    {isOrganization ? 'Full Address' : 'Address'}
                  </label>
                  <textarea name="fullAddress" value={form.fullAddress} onChange={handleChange} className="input-field min-h-[120px] resize-none" placeholder="House no, street, landmark" />
                  <FieldError message={errors.fullAddress} />
                </div>
                <div>
                  <label className="block text-xs font-bold text-white mb-2 uppercase tracking-widest opacity-60">Location (lat,lng)</label>
                  <div className="space-y-3">
                    <input name="location" value={form.location} onChange={handleChange} className="input-field" placeholder="28.61390,77.20900" />
                    <button type="button" onClick={detectLocation} className="w-full py-3 rounded-2xl border border-white/10 bg-white/5 hover:bg-white/10 text-sm font-bold text-white transition-all">
                      Auto Detect Location
                    </button>
                  </div>
                  <FieldError message={errors.location} />
                </div>
              </div>
            </section>

            {isOrganization ? (
              <>
                <section className="space-y-6">
                  <h2 className="text-lg font-black text-white">Organization Details</h2>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div>
                      <label className="block text-xs font-bold text-white mb-2 uppercase tracking-widest opacity-60">Organization Type</label>
                      <select name="orgType" value={form.orgType} onChange={handleChange} className="input-field">
                        {ORG_TYPES.map((option) => <option key={option} value={option}>{option.replace(/_/g, ' ')}</option>)}
                      </select>
                      <FieldError message={errors.orgType} />
                    </div>
                    <div>
                      <label className="block text-xs font-bold text-white mb-2 uppercase tracking-widest opacity-60">Registration Number</label>
                      <input name="registrationNumber" value={form.registrationNumber} onChange={handleChange} className="input-field" placeholder="Govt registration ID" />
                      <FieldError message={errors.registrationNumber} />
                    </div>
                  </div>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <label className="glass-card p-4 border border-white/10 cursor-pointer hover:border-brand-500/30 transition-all">
                      <span className="block text-xs font-bold text-white uppercase tracking-widest opacity-60 mb-2">Pickup Available</span>
                      <input type="checkbox" name="pickupAvailable" checked={Boolean(form.pickupAvailable)} onChange={handleChange} className="mr-2" />
                      <span className="text-white text-sm">Our team can arrange pickup</span>
                    </label>
                    <label className="glass-card p-4 border border-white/10 cursor-pointer hover:border-brand-500/30 transition-all">
                      <span className="block text-xs font-bold text-white uppercase tracking-widest opacity-60 mb-2">Delivery Required</span>
                      <input type="checkbox" name="deliveryRequired" checked={Boolean(form.deliveryRequired)} onChange={handleChange} className="mr-2" />
                      <span className="text-white text-sm">We usually need incoming delivery support</span>
                    </label>
                  </div>
                </section>

                <section className="space-y-6">
                  <div className="flex items-center justify-between">
                    <h2 className="text-lg font-black text-white">Verification</h2>
                    <span className="px-3 py-1 rounded-full bg-amber-500/10 text-amber-300 text-xs font-bold uppercase tracking-widest">
                      Pending admin approval
                    </span>
                  </div>

                  <div className="p-4 bg-amber-500/5 border border-amber-500/20 rounded-2xl">
                    <p className="text-sm text-amber-100">
                      Account will be activated after admin verification.
                    </p>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div>
                      <label className="block text-xs font-bold text-white mb-2 uppercase tracking-widest opacity-60">Upload Document</label>
                      <input type="file" accept=".pdf,image/*" onChange={handleDocumentChange} className="input-field file:mr-3 file:rounded-xl file:border-0 file:bg-brand-500/20 file:px-3 file:py-2 file:text-xs file:font-bold file:text-brand-200" />
                      {form.documentName ? <p className="text-xs text-slate-400 mt-2">{form.documentName}</p> : null}
                      <FieldError message={errors.documentUrl} />
                    </div>
                    <div className="glass-card p-4 border border-white/10 min-h-[170px]">
                      <p className="text-xs font-bold text-white uppercase tracking-widest opacity-60 mb-3">Preview</p>
                      {documentPreview ? (
                        <img src={documentPreview} alt="Verification preview" className="w-full h-28 object-cover rounded-xl" />
                      ) : (
                        <div className="h-28 rounded-xl border border-dashed border-white/10 flex items-center justify-center text-slate-500 text-sm">
                          Image preview appears here. PDF files show filename above.
                        </div>
                      )}
                    </div>
                  </div>
                </section>
              </>
            ) : null}

            <button type="submit" disabled={loading} className="btn-primary w-full py-4 font-black tracking-widest uppercase shadow-xl shadow-brand-500/20">
              {loading ? <Loader size="sm" color="white" /> : isOrganization ? 'Submit For Verification' : 'Create Account'}
            </button>
          </form>

          <p className="mt-8 text-center text-sm text-slate-500 font-medium">
            Already have an account?{' '}
            <Link to="/login" className="text-brand-400 font-bold hover:underline">Log In</Link>
          </p>
        </div>
      </div>
    </div>
  );
}
