import { useCallback, useEffect, useMemo, useState } from 'react';
import { Link, useNavigate, useParams } from 'react-router-dom';
import toast from 'react-hot-toast';
import Loader from '../components/Loader';
import { getAllFood, getOrganizations, verifyOrganization } from '../services/api';
import { formatEnumLabel, safeText } from '../utils/workflow';

function DetailCard({ label, value, accent = 'text-white' }) {
  return (
    <div className="rounded-[24px] border border-slate-800/80 bg-white/[0.035] p-4">
      <p className="text-[10px] font-semibold uppercase tracking-[0.22em] text-slate-500">{label}</p>
      <p className={`mt-2 text-sm font-medium leading-6 ${accent}`}>{value}</p>
    </div>
  );
}

export default function AdminOrganizationWorkspace() {
  const { orgId } = useParams();
  const navigate = useNavigate();
  const [organizations, setOrganizations] = useState([]);
  const [donations, setDonations] = useState([]);
  const [loading, setLoading] = useState(true);

  const refreshPage = useCallback(async () => {
    try {
      const [orgResult, donationResult] = await Promise.all([
        getOrganizations(),
        getAllFood(),
      ]);
      setOrganizations(Array.isArray(orgResult?.data) ? orgResult.data : []);
      setDonations(Array.isArray(donationResult?.data) ? donationResult.data : []);
    } catch (err) {
      toast.error(err?.response?.data?.message || 'Failed to load organization oversight');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    refreshPage();
  }, [refreshPage]);

  const organization = useMemo(
    () => organizations.find((item) => String(item?.id) === String(orgId)) || null,
    [organizations, orgId]
  );

  const relatedDonations = useMemo(
    () => donations.filter((item) => String(item?.acceptedById) === String(orgId)),
    [donations, orgId]
  );

  const handleVerify = async () => {
    if (!organization?.id) return;
    try {
      await verifyOrganization(organization.id);
      await refreshPage();
      toast.success('Organization approved');
    } catch (err) {
      toast.error(err?.response?.data?.message || 'Approval failed');
    }
  };

  if (loading) return <Loader size="lg" />;

  if (!organization) {
    return (
      <div className="glass-card rounded-[30px] p-12 text-center">
        <h1 className="text-2xl font-semibold text-white">Organization not found</h1>
        <p className="mt-3 text-slate-400">This organization may no longer exist or the link is outdated.</p>
        <button type="button" onClick={() => navigate('/dashboard')} className="btn-primary mt-6 px-6 py-3">
          Back to Admin Center
        </button>
      </div>
    );
  }

  return (
    <div className="space-y-8 animate-fade-in">
      <section className="overflow-hidden rounded-[34px] border border-slate-800/80 bg-[radial-gradient(circle_at_top_left,_rgba(59,130,246,0.16),_transparent_28%),linear-gradient(180deg,rgba(15,23,42,0.97),rgba(3,7,18,0.98))] p-7 shadow-[0_24px_90px_rgba(3,8,20,0.45)] sm:p-9">
        <div className="flex flex-col gap-6 xl:flex-row xl:items-end xl:justify-between">
          <div className="max-w-4xl">
            <Link to="/dashboard" className="inline-flex items-center gap-2 text-[11px] font-semibold uppercase tracking-[0.25em] text-slate-400 transition-colors hover:text-brand-300">
              Back to Admin Center
            </Link>
            <p className="mt-5 text-[11px] font-semibold uppercase tracking-[0.34em] text-brand-300">Organization Oversight</p>
            <h1 className="mt-3 text-3xl font-semibold tracking-tight text-white sm:text-[42px]">
              {safeText(organization.orgName || organization.name, 'Organization Record')}
            </h1>
            <p className="mt-4 max-w-3xl text-[15px] leading-7 text-slate-300">
              Administrative visibility into organization identity, verification, location, and every accepted donation.
            </p>
          </div>

          {!organization.verified ? (
            <button
              type="button"
              onClick={handleVerify}
              className="rounded-full bg-brand-600 px-5 py-3 text-[11px] font-semibold uppercase tracking-[0.2em] text-white transition-all hover:bg-brand-500"
            >
              Approve Organization
            </button>
          ) : (
            <div className="rounded-full border border-emerald-500/20 bg-emerald-500/10 px-5 py-3 text-[11px] font-semibold uppercase tracking-[0.2em] text-emerald-200">
              Verified Organization
            </div>
          )}
        </div>
      </section>

      <div className="grid gap-8 xl:grid-cols-[1.02fr_0.98fr]">
        <div className="glass-card rounded-[30px] border border-slate-800/80 p-6 sm:p-7">
          <p className="text-[11px] font-semibold uppercase tracking-[0.26em] text-slate-500">Profile Details</p>
          <div className="mt-6 grid auto-rows-fr gap-3 sm:grid-cols-2">
            <DetailCard label="Organization" value={safeText(organization.orgName || organization.name, 'Not available')} accent="text-brand-200" />
            <DetailCard label="Contact Person" value={safeText(organization.contactPersonName || organization.name, 'Not available')} />
            <DetailCard label="Email" value={safeText(organization.email, 'Not available')} />
            <DetailCard label="Mobile" value={safeText(organization.mobileNumber, 'Not available')} />
            <DetailCard label="Type" value={safeText(organization.orgType, 'Not available')} />
            <DetailCard label="Registration" value={safeText(organization.registrationNumber, 'Not available')} />
            <DetailCard label="Location" value={safeText(organization.location, 'Not available')} />
            <DetailCard label="Address" value={safeText(organization.fullAddress, 'Not available')} />
            <DetailCard label="Pickup Support" value={organization.pickupAvailable ? 'Available' : 'Not available'} />
            <DetailCard label="Delivery Support" value={organization.deliveryRequired ? 'Usually required' : 'Usually not required'} />
          </div>
        </div>

        <div className="glass-card rounded-[30px] border border-slate-800/80 p-6 sm:p-7">
          <p className="text-[11px] font-semibold uppercase tracking-[0.26em] text-slate-500">Accepted Donation Records</p>
          <div className="mt-5 space-y-3">
            {relatedDonations.length > 0 ? relatedDonations.map((donation) => (
              <button
                key={donation.id}
                type="button"
                onClick={() => navigate(`/dashboard/admin/donations/${donation.id}`)}
                className="w-full rounded-[24px] border border-slate-800/80 bg-white/[0.03] p-4 text-left transition-all hover:border-brand-500/20 hover:bg-white/[0.045]"
              >
                <div className="flex items-start justify-between gap-3">
                  <div>
                    <p className="text-sm font-semibold text-white">{safeText(donation.title, 'Donation record')}</p>
                    <p className="mt-1 text-xs text-slate-400">
                      {safeText(donation.donorName, 'Unknown donor')} | {formatEnumLabel(donation.status, 'Posted')}
                    </p>
                  </div>
                  <span className="rounded-full bg-brand-500/10 px-3 py-1 text-[10px] font-semibold uppercase tracking-[0.2em] text-brand-300">
                    Inspect
                  </span>
                </div>
              </button>
            )) : (
              <div className="rounded-[24px] border border-slate-800/80 bg-white/[0.03] px-4 py-6 text-sm text-slate-400">
                This organization has not accepted any donations yet.
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}
