import { Routes, Route, Navigate } from 'react-router-dom';
import { useAuth } from './context/AuthContext';
import Navbar from './components/Navbar';
import RouteErrorBoundary from './components/RouteErrorBoundary';
import Home from './pages/Home';
import Login from './pages/Login';
import RegisterRoleSelect from './pages/RegisterRoleSelect';
import RegisterFlow from './pages/RegisterFlow';
import PostDonation from './pages/PostDonation';

// Specific Role Dashboards
import AdminDashboard from './pages/AdminDashboardPro';
import AdminDonationWorkspace from './pages/AdminDonationWorkspace';
import AdminOrganizationWorkspace from './pages/AdminOrganizationWorkspace';
import DonorDashboard from './pages/DonorDashboardOverview';
import DonorDonationWorkspace from './pages/DonorDonationWorkspace';
import OrgDashboard from './pages/OrgDashboardOverview';
import OrgDonationWorkspace from './pages/OrgDonationWorkspace';

function ProtectedRoute({ children, roles }) {
  const { user, isAuthenticated } = useAuth();
  if (!isAuthenticated) return <Navigate to="/login" replace />;
  if (roles && !roles.includes(user.role)) return <Navigate to="/dashboard" replace />;
  return children;
}

function GuestRoute({ children }) {
  const { isAuthenticated } = useAuth();
  return !isAuthenticated ? children : <Navigate to="/dashboard" replace />;
}

function RoleBasedDashboard() {
  const { user } = useAuth();
  if (user?.role === 'ADMIN') return <AdminDashboard />;
  if (user?.role === 'DONOR') return <DonorDashboard />;
  if (user?.role === 'ORGANIZATION') return <OrgDashboard />;
  return <Navigate to="/login" replace />;
}

export default function App() {
  const { user } = useAuth();

  return (
    <div className="gradient-bg min-h-screen text-slate-200">
      <Navbar />
      <div className="container mx-auto px-4 py-8 max-w-7xl">
        <Routes>
          <Route path="/" element={<Home />} />
          <Route path="/login" element={<GuestRoute><Login /></GuestRoute>} />
          <Route path="/register" element={<GuestRoute><RegisterRoleSelect /></GuestRoute>} />
          <Route path="/register/:role" element={<GuestRoute><RegisterFlow /></GuestRoute>} />

          <Route
            path="/dashboard"
            element={
              <ProtectedRoute>
                <RouteErrorBoundary>
                  <RoleBasedDashboard />
                </RouteErrorBoundary>
              </ProtectedRoute>
            }
          />

          <Route
            path="/dashboard/donations/:donationId"
            element={
              <ProtectedRoute roles={['DONOR']}>
                <RouteErrorBoundary>
                  <DonorDonationWorkspace />
                </RouteErrorBoundary>
              </ProtectedRoute>
            }
          />

          <Route
            path="/dashboard/requests/:donationId"
            element={
              <ProtectedRoute roles={['ORGANIZATION']}>
                <RouteErrorBoundary>
                  <OrgDonationWorkspace />
                </RouteErrorBoundary>
              </ProtectedRoute>
            }
          />

          <Route
            path="/dashboard/admin/donations/:donationId"
            element={
              <ProtectedRoute roles={['ADMIN']}>
                <RouteErrorBoundary>
                  <AdminDonationWorkspace />
                </RouteErrorBoundary>
              </ProtectedRoute>
            }
          />

          <Route
            path="/dashboard/admin/organizations/:orgId"
            element={
              <ProtectedRoute roles={['ADMIN']}>
                <RouteErrorBoundary>
                  <AdminOrganizationWorkspace />
                </RouteErrorBoundary>
              </ProtectedRoute>
            }
          />

          <Route path="/post-food" element={
            <ProtectedRoute roles={['DONOR']}>
              <PostDonation />
            </ProtectedRoute>
          } />

          <Route path="/post-donation" element={<Navigate to="/post-food" replace />} />

          <Route path="*" element={<Navigate to={user ? '/dashboard' : '/'} replace />} />
        </Routes>
      </div>
    </div>
  );
}
