import React from 'react';
import { MapContainer, TileLayer, Marker, Popup, Polyline } from 'react-leaflet';
import L from 'leaflet';
import 'leaflet/dist/leaflet.css';

// Fix for default marker icons in Leaflet + React/Vite
import icon from 'leaflet/dist/images/marker-icon.png';
import iconShadow from 'leaflet/dist/images/marker-shadow.png';

let DefaultIcon = L.icon({
    iconUrl: icon,
    shadowUrl: iconShadow,
    iconAnchor: [12, 41]
});

L.Marker.prototype.options.icon = DefaultIcon;

class LeafletErrorBoundary extends React.Component {
  constructor(props) {
    super(props);
    this.state = { hasError: false };
  }

  static getDerivedStateFromError() {
    return { hasError: true };
  }

  componentDidCatch(error) {
    console.error('Leaflet map crashed', error);
  }

  render() {
    if (this.state.hasError) return this.props.fallback ?? null;
    return this.props.children;
  }
}

const MapView = ({ donorLoc, orgLoc, donorName, orgName }) => {
  const parseLoc = (loc) => {
    try {
      if (!loc || typeof loc !== 'string') return null;
      const parts = loc.split(',');
      if (parts.length < 2) return null;
      const lat = parseFloat(parts[0]);
      const lng = parseFloat(parts[1]);
      return (isNaN(lat) || isNaN(lng)) ? null : [lat, lng];
    } catch (e) {
      console.error('Error parsing location:', loc, e);
      return null;
    }
  };

  const renderFallback = () => (
    <div className="h-[350px] w-full rounded-2xl overflow-hidden glass-card border-white/10 z-0 p-6 flex flex-col justify-center">
      <h3 className="text-white font-bold text-lg">Location Summary</h3>
      <p className="text-slate-400 text-sm mt-3">
        Donor: <span className="text-white">{donorName || 'Donor'}</span>
      </p>
      <p className="text-slate-400 text-sm mt-2 break-all">
        Donor coordinates: <span className="text-white">{donorLoc || 'Not shared'}</span>
      </p>
      {orgLoc ? (
        <>
          <p className="text-slate-400 text-sm mt-4">
            Destination: <span className="text-white">{orgName || 'Organization'}</span>
          </p>
          <p className="text-slate-400 text-sm mt-2 break-all">
            Destination coordinates: <span className="text-white">{orgLoc}</span>
          </p>
        </>
      ) : null}
      <p className="text-slate-500 text-xs mt-4">
        Live map preview is unavailable for this item, but the delivery workflow still works.
      </p>
    </div>
  );

  try {
    const dPos = parseLoc(donorLoc);
    const oPos = parseLoc(orgLoc);

    if (!dPos && !oPos) {
      return renderFallback();
    }

    let center = [20.5937, 78.9629];
    if (dPos) {
      center = oPos
        ? [(dPos[0] + oPos[0]) / 2, (dPos[1] + oPos[1]) / 2]
        : dPos;
    } else if (oPos) {
      center = oPos;
    }

    const zoom = (dPos && oPos) ? 12 : 13;
    const mapKey = `${dPos ? dPos.join(',') : 'none'}|${oPos ? oPos.join(',') : 'none'}`;

    return (
      <LeafletErrorBoundary key={mapKey} fallback={renderFallback()}>
        <div className="h-[350px] w-full rounded-2xl overflow-hidden glass-card border-white/10 z-0">
          <MapContainer
            key={mapKey}
            center={center}
            zoom={zoom}
            className="w-full h-full"
            scrollWheelZoom={false}
          >
            <TileLayer
              url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
              attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>'
            />

            {dPos ? (
              <Marker position={dPos}>
                <Popup>
                  <div>
                    <div className="text-dark-900 font-semibold">{donorName || 'Donor'}</div>
                    <div className="text-xs">Donor Location</div>
                  </div>
                </Popup>
              </Marker>
            ) : null}

            {oPos ? (
              <Marker position={oPos}>
                <Popup>
                  <div>
                    <div className="text-dark-900 font-semibold">{orgName || 'Organization'}</div>
                    <div className="text-xs">Target Location</div>
                  </div>
                </Popup>
              </Marker>
            ) : null}

            {dPos && oPos ? (
              <Polyline positions={[dPos, oPos]} color="#06b6d4" weight={3} dashArray="10, 10" />
            ) : null}
          </MapContainer>
        </div>
      </LeafletErrorBoundary>
    );
  } catch (error) {
    console.error('MapView render failed', error);
    return renderFallback();
  }
};

export default MapView;
