import { createContext, useContext, useMemo, useState } from 'react';

const RegistrationContext = createContext(null);

const donorDefaults = {
  role: 'DONOR',
  name: '',
  email: '',
  password: '',
  confirmPassword: '',
  mobileNumber: '',
  fullAddress: '',
  pinCode: '',
  state: '',
  district: '',
  location: '',
};

const organizationDefaults = {
  role: 'ORGANIZATION',
  orgName: '',
  contactPersonName: '',
  email: '',
  password: '',
  confirmPassword: '',
  mobileNumber: '',
  fullAddress: '',
  pinCode: '',
  state: '',
  district: '',
  location: '',
  orgType: 'NGO',
  registrationNumber: '',
  documentUrl: '',
  documentName: '',
  pickupAvailable: true,
  deliveryRequired: true,
};

export function RegistrationProvider({ children }) {
  const [selectedRole, setSelectedRole] = useState(null);
  const [donorDraft, setDonorDraft] = useState(donorDefaults);
  const [organizationDraft, setOrganizationDraft] = useState(organizationDefaults);

  const value = useMemo(() => ({
    selectedRole,
    setSelectedRole,
    donorDraft,
    setDonorDraft,
    organizationDraft,
    setOrganizationDraft,
    resetRegistration: () => {
      setSelectedRole(null);
      setDonorDraft(donorDefaults);
      setOrganizationDraft(organizationDefaults);
    },
  }), [selectedRole, donorDraft, organizationDraft]);

  return (
    <RegistrationContext.Provider value={value}>
      {children}
    </RegistrationContext.Provider>
  );
}

export function useRegistration() {
  const ctx = useContext(RegistrationContext);
  if (!ctx) throw new Error('useRegistration must be used within RegistrationProvider');
  return ctx;
}
