import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { Link, useNavigate, useParams } from 'react-router-dom';
import toast from 'react-hot-toast';
import ConfirmModal from '../components/ConfirmModal';
import DeliveryChatPanel from '../components/DeliveryChatPanel';
import Loader from '../components/Loader';
import MapView from '../components/MapView';
import ProgressBar from '../components/ProgressBar';
import { deleteFood, getMyFood, selectDeliveryMode, updateFoodStatus } from '../services/api';
import {
  buildDeliveryToast,
  formatConditionLabel,
  formatDateTime,
  formatEnumLabel,
  getAgreementStatus,
  getPartnerLabel,
  isPartnerAssistedMode,
  safeText,
} from '../utils/workflow';
import { calculateDistanceKm, getDistanceLabel } from '../utils/orgDashboard';

function SnapshotCard({ label, value, accent = 'text-white' }) {
  return (
    <div className="rounded-3xl border border-slate-800/80 bg-white/[0.03] p-4">
      <p className="text-[10px] font-black uppercase tracking-[0.18em] text-slate-500">{label}</p>
      <p className={`mt-2 text-sm font-semibold ${accent}`}>{value}</p>
    </div>
  );
}

export default function DonorDonationWorkspace() {
  const { donationId } = useParams();
  const navigate = useNavigate();
  const [loading, setLoading] = useState(true);
  const [items, setItems] = useState([]);
  const [dialog, setDialog] = useState(null);
  const [actionBusy, setActionBusy] = useState(false);
  const previousStatusRef = useRef(null);

  const refreshDonations = useCallback(async () => {
    try {
      const { data } = await getMyFood();
      setItems(Array.isArray(data) ? data : []);
    } catch (err) {
      toast.error(err?.response?.data?.message || 'Failed to refresh this donation');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    refreshDonations();
    const interval = setInterval(refreshDonations, 4000);
    return () => clearInterval(interval);
  }, [refreshDonations]);

  const donation = useMemo(
    () => items.find((item) => String(item?.id) === String(donationId)) || null,
    [donationId, items]
  );

  const selectedStatus = String(donation?.status || 'POSTED').toUpperCase().trim();
  const deliveryLocked = Boolean(donation?.deliveryMode);
  const distanceLabel = getDistanceLabel(calculateDistanceKm(donation?.location, donation?.acceptedByLocation));

  useEffect(() => {
    if (!donation?.id) return;
    const previousStatus = previousStatusRef.current;
    if (previousStatus === 'POSTED' && selectedStatus === 'ACCEPTED' && donation?.acceptedByName) {
      toast.success(`Accepted by ${donation.acceptedByName}`);
    }
    previousStatusRef.current = selectedStatus;
  }, [donation?.acceptedByName, donation?.id, selectedStatus]);

  const handleSelectDelivery = useCallback(async (mode) => {
    if (!donation?.id) return;

    try {
      const { data } = await selectDeliveryMode(donation.id, mode);
      setItems((current) => current.map((item) => (item?.id === data?.id ? data : item)));
      toast.success(buildDeliveryToast(data, mode));
      return data;
    } catch (err) {
      toast.error(err?.response?.data?.message || 'Failed to share delivery choice');
      throw err;
    }
  }, [donation?.id]);

  const performStatusUpdate = useCallback(async (status) => {
    if (!donation?.id) return;

    try {
      const { data } = await updateFoodStatus(donation.id, status);
      setItems((current) => current.map((item) => (item?.id === data?.id ? data : item)));
      toast.success(`Status updated to ${formatEnumLabel(status)}`);
      return data;
    } catch (err) {
      toast.error(err?.response?.data?.message || 'Update failed');
      throw err;
    }
  }, [donation?.id]);

  const handleDeleteDonation = useCallback(async () => {
    if (!donation?.id) return;

    try {
      await deleteFood(donation.id);
      toast.success('Donation deleted');
      navigate('/dashboard');
    } catch (err) {
      toast.error(err?.response?.data?.message || 'Delete failed');
      throw err;
    }
  }, [donation?.id, navigate]);

  const closeDialog = useCallback(() => {
    if (!actionBusy) setDialog(null);
  }, [actionBusy]);

  const handleConfirmDialog = useCallback(async () => {
    if (!dialog) return;

    setActionBusy(true);
    try {
      if (dialog.type === 'delete') {
        await handleDeleteDonation();
      }
      if (dialog.type === 'status') {
        await performStatusUpdate(dialog.status);
      }
      setDialog(null);
    } finally {
      setActionBusy(false);
    }
  }, [dialog, handleDeleteDonation, performStatusUpdate]);

  const canUpdatePreference = selectedStatus !== 'PICKUP_STARTED' && selectedStatus !== 'DELIVERED';

  if (loading) return <Loader size="lg" />;

  if (!donation) {
    return (
      <div className="glass-card rounded-[30px] p-12 text-center">
        <h1 className="text-2xl font-black text-white">Donation not found</h1>
        <p className="mt-3 text-slate-400">
          This donation may have been removed, or the page was opened with an outdated link.
        </p>
        <button type="button" onClick={() => navigate('/dashboard')} className="btn-primary mt-6 px-6 py-3">
          Back to Dashboard
        </button>
      </div>
    );
  }

  return (
    <div className="space-y-8 animate-fade-in">
      <section className="overflow-hidden rounded-[34px] border border-slate-800/80 bg-[radial-gradient(circle_at_top_left,_rgba(16,185,129,0.20),_transparent_30%),linear-gradient(180deg,rgba(15,23,42,0.98),rgba(3,7,18,0.98))] p-7 sm:p-9 shadow-[0_24px_90px_rgba(3,8,20,0.45)]">
        <div className="flex flex-col gap-6 xl:flex-row xl:items-end xl:justify-between">
          <div className="max-w-4xl">
            <Link to="/dashboard" className="inline-flex items-center gap-2 text-xs font-black uppercase tracking-[0.25em] text-slate-400 transition-colors hover:text-brand-300">
              Back to My Donations
            </Link>
            <p className="mt-5 text-xs font-black uppercase tracking-[0.35em] text-brand-300">Donation Record</p>
            <h1 className="mt-3 text-4xl font-black tracking-tight text-white sm:text-5xl">
              {safeText(donation.title, 'Untitled donation')}
            </h1>
            <p className="mt-4 max-w-3xl text-base leading-7 text-slate-300">
              {getAgreementStatus(donation)}
            </p>
          </div>

          <div className="flex flex-wrap gap-3">
            <div className="rounded-3xl border border-slate-800/80 bg-white/[0.04] px-5 py-4">
              <p className="text-[10px] font-black uppercase tracking-[0.22em] text-slate-500">Status</p>
              <p className="mt-2 text-xl font-black text-white">{formatEnumLabel(selectedStatus, 'Posted')}</p>
            </div>
            <div className="rounded-3xl border border-slate-800/80 bg-white/[0.04] px-5 py-4">
              <p className="text-[10px] font-black uppercase tracking-[0.22em] text-slate-500">Final Path</p>
              <p className="mt-2 text-xl font-black text-white">
                {formatEnumLabel(donation.deliveryMode, 'Still deciding')}
              </p>
            </div>
          </div>
        </div>
      </section>

      <div className="grid gap-8 xl:grid-cols-[1.08fr_0.92fr]">
        <div className="space-y-6">
          <div className="glass-card rounded-[30px] border border-slate-800/80 p-6 sm:p-7">
            <div className="flex flex-wrap items-start justify-between gap-4">
              <div>
                <p className="text-xs font-black uppercase tracking-[0.25em] text-slate-500">Overview</p>
                <h2 className="mt-2 text-2xl font-black text-white">Everything about this donation</h2>
              </div>
              <span className="rounded-full border border-brand-500/20 bg-brand-500/10 px-4 py-2 text-xs font-black uppercase tracking-[0.22em] text-brand-300">
                {formatEnumLabel(donation.category, 'Donation')}
              </span>
            </div>

            <div className="mt-6 grid gap-3 sm:grid-cols-2 xl:grid-cols-3">
              <SnapshotCard label="Item Type" value={safeText(donation.type, 'Food item')} />
              <SnapshotCard label="Quantity" value={safeText(donation.quantity, '0')} />
              <SnapshotCard label="Condition" value={formatConditionLabel(donation.condition, 'Not specified')} />
              <SnapshotCard label="Expiry" value={formatDateTime(donation.expiryTime)} />
              <SnapshotCard label="Organization" value={safeText(donation.acceptedByName, 'Waiting for organization')} />
              <SnapshotCard label="Distance" value={distanceLabel} />
              <SnapshotCard
                label="Your Choice"
                value={formatEnumLabel(donation.donorDeliveryPreference, 'You have not chosen yet')}
                accent="text-brand-200"
              />
              <div className="rounded-3xl border border-slate-800/80 bg-white/[0.03] p-4 sm:col-span-2 xl:col-span-3">
                <p className="text-[10px] font-black uppercase tracking-[0.18em] text-slate-500">Pickup Location</p>
                <p className="mt-2 text-sm font-semibold text-white">{safeText(donation.location, 'Not shared')}</p>
              </div>
            </div>

            <div className="mt-6">
              <ProgressBar status={selectedStatus} deliveryMode={donation?.deliveryMode} />
            </div>

            {canUpdatePreference ? (
              <div className="mt-6 rounded-3xl border border-slate-800/80 bg-white/[0.03] p-4">
                <div className="flex flex-wrap items-center justify-between gap-3">
                  <div>
                    <p className="text-[10px] font-black uppercase tracking-[0.18em] text-slate-500">Delivery Decision</p>
                    <p className="mt-1 text-sm text-slate-300">After reviewing the organization and distance, you can still change your mind before pickup starts.</p>
                  </div>
                  <div className="flex flex-wrap gap-2">
                    <button
                      type="button"
                      onClick={() => handleSelectDelivery('DONOR_DELIVERY')}
                      className={`rounded-full px-4 py-2 text-[11px] font-semibold uppercase tracking-[0.18em] transition-all ${
                        donation?.donorDeliveryPreference === 'DONOR_DELIVERY'
                          ? 'bg-brand-500/15 text-brand-200'
                          : 'bg-slate-900 text-slate-300 hover:bg-slate-800'
                      }`}
                    >
                      I Will Deliver
                    </button>
                    <button
                      type="button"
                      onClick={() => handleSelectDelivery('ORG_PICKUP')}
                      className={`rounded-full px-4 py-2 text-[11px] font-semibold uppercase tracking-[0.18em] transition-all ${
                        donation?.donorDeliveryPreference === 'ORG_PICKUP'
                          ? 'bg-brand-500/15 text-brand-200'
                          : 'bg-slate-900 text-slate-300 hover:bg-slate-800'
                      }`}
                    >
                      Need Pickup
                    </button>
                  </div>
                </div>
              </div>
            ) : null}

            {deliveryLocked && selectedStatus !== 'DELIVERED' ? (
              <div className="mt-6 flex flex-wrap gap-3">
                {selectedStatus === 'ACCEPTED' ? (
                  <button
                    type="button"
                    onClick={() => setDialog({
                      type: 'status',
                      status: 'PICKUP_STARTED',
                      title: 'Confirm Pickup',
                      message: 'Mark this only after the donation has actually been picked up from you.',
                      confirmLabel: 'Mark Picked Up',
                    })}
                    className="btn-primary px-5 py-3 text-xs font-black uppercase tracking-[0.22em]"
                  >
                    Mark Picked Up
                  </button>
                ) : null}
                {selectedStatus === 'PICKUP_STARTED' ? (
                  <div className="rounded-2xl border border-sky-500/20 bg-sky-500/10 px-4 py-3 text-xs font-semibold text-sky-100">
                    Pickup is confirmed. The organization will mark the donation delivered after final handoff.
                  </div>
                ) : null}
                {selectedStatus === 'PENDING_NGO' ? (
                  <div className="rounded-2xl border border-amber-500/20 bg-amber-500/10 px-4 py-3 text-xs font-semibold text-amber-200">
                    {isPartnerAssistedMode(donation?.deliveryMode)
                      ? `${formatEnumLabel(donation.deliveryMode)} is approved, but pickup can only begin after the ${getPartnerLabel(donation.deliveryMode)} is assigned.`
                      : 'Pickup is waiting for partner assignment.'}
                  </div>
                ) : null}
              </div>
            ) : null}

            {selectedStatus === 'POSTED' ? (
              <div className="mt-6">
                <button
                  type="button"
                  onClick={() => setDialog({
                    type: 'delete',
                    title: 'Delete Donation',
                    message: 'This will permanently remove the posted donation. Use this only if you shared the wrong food details.',
                    confirmLabel: 'Delete Donation',
                    tone: 'danger',
                  })}
                  className="rounded-2xl border border-rose-500/20 bg-rose-500/10 px-5 py-3 text-xs font-black uppercase tracking-[0.22em] text-rose-100 transition-all hover:bg-rose-500/20"
                >
                  Delete Donation
                </button>
              </div>
            ) : null}
          </div>

          <DeliveryChatPanel
            foodId={donation.id}
            status={selectedStatus}
            foodData={donation}
            onSelectDelivery={handleSelectDelivery}
            onWorkflowUpdate={refreshDonations}
          />
        </div>

        <div className="space-y-6">
          {donation?.acceptedByName ? (
            <div className="glass-card rounded-[30px] border border-slate-800/80 p-6 sm:p-7">
              <p className="text-xs font-black uppercase tracking-[0.25em] text-slate-500">Organization Details</p>
              <div className="mt-5 grid gap-3">
                <SnapshotCard label="Name" value={safeText(donation.acceptedByName, 'Not assigned')} accent="text-brand-200" />
                <SnapshotCard label="Contact" value={safeText(donation.acceptedByContact, 'Not available')} />
                <SnapshotCard label="Distance" value={distanceLabel} />
                <SnapshotCard
                  label="Pickup Facility"
                  value={donation?.acceptedByPickupAvailable ? 'Available' : 'Confirm in chat'}
                />
              </div>
              {donation?.acceptedByAddress ? (
                <div className="mt-3 rounded-3xl border border-slate-800/80 bg-white/[0.03] p-4">
                  <p className="text-[10px] font-black uppercase tracking-[0.18em] text-slate-500">Address</p>
                  <p className="mt-2 text-sm font-semibold text-white">{donation.acceptedByAddress}</p>
                </div>
              ) : null}
            </div>
          ) : null}

          <MapView donorLoc={donation.location} donorName="Donation Location" />
        </div>
      </div>

      <ConfirmModal
        open={Boolean(dialog)}
        title={dialog?.title}
        message={dialog?.message}
        confirmLabel={dialog?.confirmLabel}
        tone={dialog?.tone}
        busy={actionBusy}
        onConfirm={handleConfirmDialog}
        onClose={closeDialog}
      />
    </div>
  );
}
