export const ensureArray = (value) => (Array.isArray(value) ? value : []);

export function calculateDistanceKm(origin, destination) {
  const parsePoint = (value) => {
    if (!value || typeof value !== 'string' || !value.includes(',')) return null;
    const [lat, lng] = value.split(',').map((item) => Number(item.trim()));
    if (Number.isNaN(lat) || Number.isNaN(lng)) return null;
    return { lat, lng };
  };

  const start = parsePoint(origin);
  const end = parsePoint(destination);
  if (!start || !end) return null;

  const toRad = (degrees) => (degrees * Math.PI) / 180;
  const earthKm = 6371;
  const latDiff = toRad(end.lat - start.lat);
  const lngDiff = toRad(end.lng - start.lng);
  const a = Math.sin(latDiff / 2) ** 2
    + Math.cos(toRad(start.lat)) * Math.cos(toRad(end.lat)) * Math.sin(lngDiff / 2) ** 2;

  return Math.round((earthKm * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a))) * 10) / 10;
}

export function dedupeById(items) {
  const seen = new Set();
  return ensureArray(items).filter((item) => {
    if (!item || typeof item !== 'object') return false;
    const key = item.id ?? `${item.foodType}-${item.quantity}-${item.location}`;
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  });
}

export function describeScore(score) {
  if (score == null) return 'Score unavailable';
  if (score >= 15) return 'Best nearby match';
  if (score >= 10) return 'Strong nearby match';
  if (score >= 6) return 'Good nearby match';
  return 'Possible match';
}

export function getDistanceLabel(distanceKm) {
  return distanceKm == null ? 'Distance unavailable' : `${distanceKm} km away`;
}

function getExpiryTimestamp(value) {
  if (!value) return Number.POSITIVE_INFINITY;
  const timestamp = new Date(value).getTime();
  return Number.isNaN(timestamp) ? Number.POSITIVE_INFINITY : timestamp;
}

export function sortOpportunities(items, orgLocation) {
  return [...ensureArray(items)].sort((left, right) => {
    if (Boolean(left?.recommended) !== Boolean(right?.recommended)) {
      return left?.recommended ? -1 : 1;
    }

    const leftScore = Number(left?.aiScore ?? -1);
    const rightScore = Number(right?.aiScore ?? -1);
    if (leftScore !== rightScore) return rightScore - leftScore;

    const leftDistance = calculateDistanceKm(orgLocation, left?.location);
    const rightDistance = calculateDistanceKm(orgLocation, right?.location);

    if (leftDistance == null && rightDistance != null) return 1;
    if (leftDistance != null && rightDistance == null) return -1;
    if (leftDistance != null && rightDistance != null && leftDistance !== rightDistance) {
      return leftDistance - rightDistance;
    }

    const leftExpiry = getExpiryTimestamp(left?.expiryTime);
    const rightExpiry = getExpiryTimestamp(right?.expiryTime);
    if (leftExpiry !== rightExpiry) return leftExpiry - rightExpiry;

    return String(left?.title ?? '').localeCompare(String(right?.title ?? ''));
  });
}
