import { useEffect } from 'react';
import { createPortal } from 'react-dom';

export default function ConfirmModal({
  open,
  title,
  message,
  confirmLabel = 'Confirm',
  cancelLabel = 'Cancel',
  tone = 'brand',
  busy = false,
  onConfirm,
  onClose,
}) {
  useEffect(() => {
    if (!open) return undefined;

    const previousOverflow = document.body.style.overflow;
    const previousPaddingRight = document.body.style.paddingRight;
    const scrollbarWidth = window.innerWidth - document.documentElement.clientWidth;

    document.body.style.overflow = 'hidden';
    if (scrollbarWidth > 0) {
      document.body.style.paddingRight = `${scrollbarWidth}px`;
    }

    return () => {
      document.body.style.overflow = previousOverflow;
      document.body.style.paddingRight = previousPaddingRight;
    };
  }, [open]);

  if (!open) return null;

  const toneClasses = tone === 'danger'
    ? 'bg-rose-600 hover:bg-rose-500'
    : 'bg-brand-600 hover:bg-brand-500';

  return createPortal(
    <div className="fixed inset-0 z-[120] flex items-center justify-center bg-slate-950/75 px-4 backdrop-blur-sm">
      <div className="w-full max-w-md rounded-[28px] border border-slate-800/80 bg-[linear-gradient(180deg,rgba(15,23,42,0.98),rgba(2,6,23,0.98))] p-6 shadow-[0_28px_100px_rgba(2,6,23,0.75)]">
        <p className="text-[11px] font-semibold uppercase tracking-[0.28em] text-slate-500">Confirmation</p>
        <h2 className="mt-3 text-2xl font-semibold tracking-tight text-white">{title}</h2>
        <p className="mt-3 text-sm leading-7 text-slate-300">{message}</p>

        <div className="mt-6 flex flex-wrap justify-end gap-3">
          <button
            type="button"
            onClick={onClose}
            disabled={busy}
            className="rounded-full border border-slate-700/80 bg-white/[0.04] px-5 py-3 text-[11px] font-semibold uppercase tracking-[0.22em] text-slate-200 transition-all hover:border-slate-500/70 hover:text-white disabled:cursor-not-allowed disabled:opacity-60"
          >
            {cancelLabel}
          </button>
          <button
            type="button"
            onClick={onConfirm}
            disabled={busy}
            className={`rounded-full px-5 py-3 text-[11px] font-semibold uppercase tracking-[0.22em] text-white transition-all disabled:cursor-not-allowed disabled:opacity-60 ${toneClasses}`}
          >
            {busy ? 'Please Wait' : confirmLabel}
          </button>
        </div>
      </div>
    </div>,
    document.body
  );
}
