export const CHAT_READY_STATUSES = new Set(['ACCEPTED', 'PENDING_NGO', 'PICKUP_STARTED', 'DELIVERED']);

export const DELIVERY_MODE_LABELS = {
  DONOR_DELIVERY: 'Direct Donor Delivery',
  ORG_PICKUP: 'Organization Pickup',
  NGO_DELIVERY: 'Nearby NGO Support',
  DELIVERY_PARTNER: 'Delivery Partner',
};

export const FOOD_CONDITION_LABELS = {
  NEW: 'Freshly Prepared',
  USED: 'Stored / Packaged',
};

export function isPartnerAssistedMode(mode) {
  return mode === 'NGO_DELIVERY' || mode === 'DELIVERY_PARTNER';
}

export function getPartnerLabel(mode) {
  if (mode === 'NGO_DELIVERY') return 'NGO partner';
  if (mode === 'DELIVERY_PARTNER') return 'delivery partner';
  return 'partner';
}

export function getPartnerHeading(mode) {
  if (mode === 'NGO_DELIVERY') return 'NGO Partner';
  if (mode === 'DELIVERY_PARTNER') return 'Delivery Partner';
  return 'Partner';
}

export function safeText(value, fallback = 'Unknown') {
  if (typeof value === 'string' && value.trim()) return value;
  if (typeof value === 'number') return String(value);
  return fallback;
}

export function formatEnumLabel(value, fallback = 'Not set') {
  const normalized = typeof value === 'string' ? value.trim() : '';
  if (!normalized) return fallback;
  if (DELIVERY_MODE_LABELS[normalized]) return DELIVERY_MODE_LABELS[normalized];
  return normalized
    .toLowerCase()
    .split('_')
    .map((part) => part.charAt(0).toUpperCase() + part.slice(1))
    .join(' ');
}

export function formatConditionLabel(value, fallback = 'Not specified') {
  const normalized = typeof value === 'string' ? value.trim() : '';
  if (!normalized) return fallback;
  return FOOD_CONDITION_LABELS[normalized] || formatEnumLabel(normalized, fallback);
}

export function formatDateTime(value) {
  if (!value) return 'Not set';
  try {
    return new Date(value).toLocaleString();
  } catch {
    return 'Not set';
  }
}

export function isDeliveryAgreementReached(food) {
  return Boolean(food?.deliveryAgreementReached || food?.deliveryMode);
}

export function buildDeliveryToast(response, requestedMode) {
  if (isDeliveryAgreementReached(response)) {
    return `Delivery path locked: ${formatEnumLabel(response?.deliveryMode, formatEnumLabel(requestedMode))}`;
  }

  if (requestedMode === 'DONOR_DELIVERY') {
    return 'Delivery choice shared. Waiting for the organization to confirm donor delivery.';
  }

  if (requestedMode === 'ORG_PICKUP') {
    return 'Pickup request shared. Waiting for the organization to choose pickup or nearby NGO support.';
  }

  return `Choice shared: ${formatEnumLabel(requestedMode)}. Waiting for the other side to match it.`;
}

export function getAgreementStatus(food) {
  const donor = food?.donorDeliveryPreference;
  const organization = food?.organizationDeliveryPreference;

  if (food?.deliveryMode) {
    if (isPartnerAssistedMode(food.deliveryMode)) {
      return food?.ngoName
        ? `${formatEnumLabel(food.deliveryMode)} is active with ${food.ngoName}.`
        : `Both sides approved ${formatEnumLabel(food.deliveryMode)}. Select the ${getPartnerLabel(food.deliveryMode)} to activate pickup.`;
    }

    return `${formatEnumLabel(food.deliveryMode)} is confirmed by both sides.`;
  }

  if (!donor && !organization) {
    return 'Delivery coordination has started. The donor should review the organization details first, then confirm the route.';
  }

  if (donor && !organization) {
    return donor === 'DONOR_DELIVERY'
      ? 'The donor is ready to deliver. Waiting for the organization to confirm direct delivery.'
      : 'The donor requested pickup support. Waiting for the organization to choose pickup or nearby NGO support.';
  }

  if (!donor && organization) {
    return 'Waiting for the donor to confirm the route after the organization updated the plan.';
  }

  return 'Both sides have responded, but the choices do not match yet. Agree on one path to continue.';
}

export function buildDeliveryAiSuggestion(food, role, distanceKm, pickupAvailable) {
  if (food?.deliveryMode === 'NGO_DELIVERY') {
    return food?.ngoName
      ? `AI suggestion: ${food.ngoName} is the strongest nearby backup route right now.`
      : 'AI suggestion: choose the nearest NGO to reduce travel delay.';
  }

  if (food?.deliveryMode === 'ORG_PICKUP') {
    return 'AI suggestion: organization pickup is the cleanest route for this donation.';
  }

  if (food?.deliveryMode === 'DONOR_DELIVERY') {
    return 'AI suggestion: direct donor delivery is the fastest confirmed route.';
  }

  if (role === 'DONOR' && food?.acceptedByName && !food?.donorDeliveryPreference) {
    if (distanceKm != null && distanceKm <= 6) {
      return 'AI suggestion: this looks close enough for direct donor delivery if timing works.';
    }
    if (food?.acceptedByPickupAvailable) {
      return 'AI suggestion: ask for organization pickup if this distance feels too long.';
    }
    return 'AI suggestion: confirm your comfort in chat, then use nearest NGO help only if pickup is not available.';
  }

  if (food?.donorDeliveryPreference === 'DONOR_DELIVERY') {
    return 'AI suggestion: confirm donor delivery quickly if your team can receive the food on time.';
  }

  if (food?.donorDeliveryPreference === 'ORG_PICKUP') {
    if (pickupAvailable) {
      return 'AI suggestion: organization pickup is the best next step if your team can travel.';
    }
    return 'AI suggestion: if pickup is not possible, assign the nearest NGO for a cleaner handoff.';
  }

  return 'AI suggestion: donor should confirm first, then the organization should match the safest route.';
}
