import React from 'react';

function buildSteps(status, deliveryMode) {
  const needsNgoStep = deliveryMode === 'NGO_DELIVERY' || deliveryMode === 'DELIVERY_PARTNER' || status === 'PENDING_NGO';

  if (needsNgoStep) {
    return [
      { value: 'POSTED', label: 'Posted' },
      { value: 'ACCEPTED', label: 'Accepted' },
      { value: 'PENDING_NGO', label: deliveryMode === 'DELIVERY_PARTNER' ? 'Partner Coordination' : 'NGO Coordination' },
      { value: 'PICKUP_STARTED', label: 'Pickup Confirmed' },
      { value: 'DELIVERED', label: 'Completed' },
    ];
  }

  return [
    { value: 'POSTED', label: 'Posted' },
    { value: 'ACCEPTED', label: 'Accepted' },
    { value: 'PICKUP_STARTED', label: 'Pickup Confirmed' },
    { value: 'DELIVERED', label: 'Completed' },
  ];
}

const ProgressBar = ({ status, deliveryMode }) => {
  const steps = buildSteps(status, deliveryMode);
  const currentIndex = Math.max(steps.findIndex((step) => step.value === status), 0);
  const progressWidth = steps.length > 1 ? (currentIndex / (steps.length - 1)) * 100 : 0;

  return (
    <div className="w-full px-2 py-6">
      <div className="relative mx-auto max-w-4xl">
        <div className="absolute left-[7%] right-[7%] top-3 h-[2px] bg-slate-800" />
        <div
          className="absolute left-[7%] top-3 h-[2px] bg-green-500 transition-all duration-700 ease-out shadow-[0_0_10px_rgba(34,197,94,0.3)]"
          style={{ width: `${progressWidth * 0.86}%` }}
        />

        <div className="relative grid gap-2" style={{ gridTemplateColumns: `repeat(${steps.length}, minmax(0, 1fr))` }}>
          {steps.map((step, index) => {
            const isCompleted = index < currentIndex;
            const isActive = index === currentIndex;

            return (
              <div key={step.value} className="flex flex-col items-center text-center">
                <div className="z-10 mb-3 flex h-6 w-6 items-center justify-center rounded-full bg-dark-900">
                  <div
                    className={`flex h-4 w-4 items-center justify-center rounded-full border-2 transition-all duration-500 ${
                      isCompleted
                        ? 'border-green-500 bg-green-500'
                        : isActive
                          ? 'border-green-500 bg-dark-900 shadow-[0_0_12px_rgba(34,197,94,0.5)]'
                          : 'border-slate-700 bg-dark-900'
                    }`}
                  >
                    {isCompleted ? <span className="h-1.5 w-1.5 rounded-full bg-white" /> : null}
                  </div>
                </div>

                <span
                  className={`block text-[10px] font-semibold uppercase tracking-[0.18em] ${
                    isActive ? 'text-white' : isCompleted ? 'text-green-400' : 'text-slate-500'
                  }`}
                >
                  {step.label}
                </span>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
};

export default ProgressBar;
