import { useEffect, useMemo, useRef, useState } from 'react';
import toast from 'react-hot-toast';
import { useAuth } from '../context/AuthContext';
import { assignNgoDelivery, getAvailableNgos, getMessages, sendMessage } from '../services/api';
import Loader from './Loader';
import {
  CHAT_READY_STATUSES,
  buildDeliveryAiSuggestion,
  formatEnumLabel,
  getPartnerHeading,
  getPartnerLabel,
  isPartnerAssistedMode,
  safeText,
} from '../utils/workflow';
import { calculateDistanceKm, getDistanceLabel } from '../utils/orgDashboard';

const DELIVERY_ACTIONS = {
  DONOR: [
    {
      mode: 'DONOR_DELIVERY',
      title: 'I will deliver',
      description: 'Choose this if you are comfortable delivering to the organization.',
    },
    {
      mode: 'ORG_PICKUP',
      title: 'I need pickup',
      description: 'Choose this if you do not want to travel and need pickup help.',
    },
  ],
  ORGANIZATION: [
    {
      mode: 'DONOR_DELIVERY',
      title: 'Confirm donor delivery',
      description: 'Use this when the donor is ready to bring the food to your organization.',
    },
    {
      mode: 'ORG_PICKUP',
      title: 'We will pick up',
      description: 'Choose this when your team can collect from the donor.',
    },
    {
      mode: 'NGO_DELIVERY',
      title: 'Ask nearby NGO',
      description: 'Choose this when your team cannot travel and a nearby NGO should help.',
    },
  ],
};

function MessageBubble({ message, ownMessage, fallbackName }) {
  if (message?.isSystem) {
    return (
      <div className="flex justify-center">
        <div className="rounded-2xl border border-slate-800/80 bg-slate-900/90 px-4 py-2 text-[11px] font-medium text-slate-300">
          {message.content}
        </div>
      </div>
    );
  }

  return (
    <div className={`flex ${ownMessage ? 'justify-end' : 'justify-start'}`}>
      <div
        className={`max-w-[85%] rounded-[24px] px-4 py-3 text-sm shadow-sm ${
          ownMessage
            ? 'bg-brand-600 text-white'
            : 'border border-slate-800/80 bg-slate-900 text-slate-100'
        }`}
      >
        <p className="text-[10px] font-black uppercase tracking-[0.18em] opacity-70">
          {ownMessage ? 'You' : safeText(message?.senderName, fallbackName)}
        </p>
        <p className="mt-2 leading-7">{message?.content}</p>
        <p className="mt-2 text-[10px] opacity-60">
          {message?.timestamp
            ? new Date(message.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
            : '--:--'}
        </p>
      </div>
    </div>
  );
}

function buildRoleSummary(role, foodData) {
  if (role === 'DONOR') {
    if (foodData?.acceptedByName && !foodData?.donorDeliveryPreference) {
      return 'Review the organization details first, then confirm whether you can deliver or need pickup.';
    }
    if (foodData?.deliveryMode === 'DONOR_DELIVERY') {
      return 'Direct donor delivery is confirmed. Finalize the timing in chat.';
    }
    if (foodData?.deliveryMode === 'ORG_PICKUP') {
      return 'Organization pickup is confirmed. Finalize handoff time in chat.';
    }
    if (isPartnerAssistedMode(foodData?.deliveryMode)) {
      return `${formatEnumLabel(foodData?.deliveryMode)} is being coordinated.`;
    }
    return 'Choose the delivery plan that feels right for you.';
  }

  if (foodData?.donorDeliveryPreference === 'DONOR_DELIVERY') {
    return 'The donor is ready to deliver directly to your organization.';
  }
  if (foodData?.donorDeliveryPreference === 'ORG_PICKUP') {
    return 'The donor needs pickup support from your side or from a nearby NGO.';
  }
  return 'Waiting for the donor to confirm the delivery preference first.';
}

function ContactCard({ label, name, contact, accent = 'text-white' }) {
  return (
    <div className="rounded-[22px] border border-slate-800/80 bg-white/[0.04] p-4">
      <p className="text-[10px] font-semibold uppercase tracking-[0.22em] text-slate-500">{label}</p>
      <p className={`mt-2 text-sm font-semibold ${accent}`}>{safeText(name, 'Not available')}</p>
      <p className="mt-1 text-xs text-slate-400">{safeText(contact, 'Contact unavailable')}</p>
    </div>
  );
}

export default function DeliveryChatPanel({ foodId, status, foodData, onSelectDelivery, onWorkflowUpdate }) {
  const { user } = useAuth();
  const [messages, setMessages] = useState([]);
  const [text, setText] = useState('');
  const [loading, setLoading] = useState(false);
  const [fetching, setFetching] = useState(true);
  const [availableNgos, setAvailableNgos] = useState([]);
  const [showNgoPicker, setShowNgoPicker] = useState(false);
  const scrollRef = useRef(null);

  const currentRole = user?.role;
  const normalizedStatus = String(status || '').toUpperCase().trim();
  const isChatEnabled = Boolean(foodId) && CHAT_READY_STATUSES.has(normalizedStatus);
  const canSendMessage = isChatEnabled;
  const currentUserChoice = currentRole === 'DONOR'
    ? foodData?.donorDeliveryPreference
    : currentRole === 'ORGANIZATION'
      ? foodData?.organizationDeliveryPreference
      : null;
  const finalMode = foodData?.deliveryMode;
  const partnerHeading = getPartnerHeading(finalMode);
  const canAssignPartner = currentRole === 'ORGANIZATION'
    && Boolean(finalMode)
    && isPartnerAssistedMode(finalMode)
    && !foodData?.ngoName;
  const distanceKm = useMemo(() => {
    if (currentRole === 'DONOR') {
      return calculateDistanceKm(foodData?.location, foodData?.acceptedByLocation);
    }
    return calculateDistanceKm(user?.location, foodData?.location);
  }, [currentRole, foodData?.acceptedByLocation, foodData?.location, user?.location]);
  const distanceLabel = getDistanceLabel(distanceKm);
  const roleSummary = buildRoleSummary(currentRole, foodData);
  const aiSuggestion = buildDeliveryAiSuggestion(
    foodData,
    currentRole,
    distanceKm,
    currentRole === 'ORGANIZATION' ? Boolean(user?.pickupAvailable) : Boolean(foodData?.acceptedByPickupAvailable)
  );
  const messageList = useMemo(() => (Array.isArray(messages) ? messages.filter(Boolean) : []), [messages]);
  const counterpartLabel = currentRole === 'DONOR'
    ? safeText(foodData?.acceptedByName, 'Organization pending')
    : safeText(foodData?.donorName, 'Donor');
  const actionOptions = useMemo(() => {
    if (currentRole === 'DONOR') {
      return DELIVERY_ACTIONS.DONOR;
    }

    if (foodData?.donorDeliveryPreference === 'DONOR_DELIVERY') {
      return DELIVERY_ACTIONS.ORGANIZATION.filter((option) => option.mode === 'DONOR_DELIVERY');
    }

    if (foodData?.donorDeliveryPreference === 'ORG_PICKUP') {
      return DELIVERY_ACTIONS.ORGANIZATION.filter((option) => option.mode === 'ORG_PICKUP' || option.mode === 'NGO_DELIVERY');
    }

    return [];
  }, [currentRole, foodData?.donorDeliveryPreference]);
  const sortedNgos = useMemo(() => (
    [...availableNgos].sort((left, right) => {
      const leftDistance = calculateDistanceKm(foodData?.location, left?.location);
      const rightDistance = calculateDistanceKm(foodData?.location, right?.location);
      if (leftDistance == null && rightDistance == null) return 0;
      if (leftDistance == null) return 1;
      if (rightDistance == null) return -1;
      return leftDistance - rightDistance;
    })
  ), [availableNgos, foodData?.location]);

  useEffect(() => {
    if (!foodId || !isChatEnabled) {
      setFetching(false);
      setMessages([]);
      return;
    }

    setFetching(true);
    const fetchMessages = async () => {
      try {
        const { data } = await getMessages(foodId);
        setMessages(Array.isArray(data) ? data.filter(Boolean) : []);
      } catch (err) {
        console.error('Failed to fetch messages', err);
      } finally {
        setFetching(false);
      }
    };

    fetchMessages();
    const interval = setInterval(fetchMessages, 2000);
    return () => clearInterval(interval);
  }, [foodId, isChatEnabled]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messageList]);

  useEffect(() => {
    setShowNgoPicker(false);
    setAvailableNgos([]);
  }, [foodId, foodData?.ngoName]);

  useEffect(() => {
    if (!canAssignPartner || availableNgos.length > 0 || showNgoPicker) return;

    const loadNearbyNgos = async () => {
      try {
        const { data } = await getAvailableNgos();
        setAvailableNgos(Array.isArray(data) ? data.filter(Boolean) : []);
        setShowNgoPicker(true);
      } catch (err) {
        console.error('Failed to load nearby NGOs', err);
      }
    };

    loadNearbyNgos();
  }, [availableNgos.length, canAssignPartner, showNgoPicker]);

  const handleSend = async (event) => {
    event.preventDefault();
    if (!text.trim() || !canSendMessage) return;

    try {
      setLoading(true);
      const { data } = await sendMessage(foodId, { content: text.trim() });
      setMessages((current) => [...current, data].filter(Boolean));
      setText('');
    } catch (err) {
      toast.error(err?.response?.data?.message || 'Failed to send message');
    } finally {
      setLoading(false);
    }
  };

  const handleSelectMode = async (mode) => {
    try {
      await onSelectDelivery?.(mode);
    } catch (err) {
      console.error(err);
    }
  };

  const handleLoadPartners = async () => {
    try {
      const { data } = await getAvailableNgos();
      setAvailableNgos(Array.isArray(data) ? data.filter(Boolean) : []);
      setShowNgoPicker(true);
    } catch (err) {
      toast.error(err?.response?.data?.message || 'Failed to load partner options');
    }
  };

  const handleAssignNgo = async (ngoId) => {
    try {
      setLoading(true);
      await assignNgoDelivery(foodId, ngoId);
      toast.success(`${partnerHeading} assigned`);
      setShowNgoPicker(false);
      onWorkflowUpdate?.();
    } catch (err) {
      toast.error(err?.response?.data?.message || 'Failed to assign partner');
    } finally {
      setLoading(false);
    }
  };

  if (!CHAT_READY_STATUSES.has(normalizedStatus)) {
    return (
      <div className="glass-card rounded-[30px] border border-slate-800/80 p-10 text-center">
        <p className="text-xs font-semibold uppercase tracking-[0.26em] text-slate-500">Delivery Desk</p>
        <h3 className="mt-3 text-2xl font-semibold text-white">Delivery coordination opens after acceptance</h3>
        <p className="mt-4 text-sm leading-7 text-slate-400">
          Once the organization accepts the donation, both sides can review contacts, confirm the route, and track the handoff from here.
        </p>
      </div>
    );
  }

  return (
    <div className="overflow-hidden rounded-[32px] border border-slate-800/80 bg-[linear-gradient(180deg,rgba(15,23,42,0.98),rgba(2,6,23,0.96))] shadow-[0_28px_100px_rgba(3,8,20,0.44)]">
      <div className="border-b border-slate-800/80 bg-[radial-gradient(circle_at_top_left,_rgba(16,185,129,0.14),_transparent_28%),linear-gradient(180deg,rgba(15,23,42,0.92),rgba(15,23,42,0.72))] p-5">
        <div className="max-w-4xl">
          <div className="flex flex-wrap items-start justify-between gap-3">
            <div>
              <p className="text-[11px] font-semibold uppercase tracking-[0.3em] text-brand-300">Delivery Desk</p>
              <h3 className="mt-3 text-2xl font-semibold tracking-tight text-white">Professional delivery coordination</h3>
              <p className="mt-2 text-sm leading-7 text-slate-300">{roleSummary}</p>
            </div>
            <div className="flex flex-wrap gap-2">
              <span className="rounded-full bg-slate-950/80 px-3 py-2 text-[11px] font-semibold text-slate-200">
                {distanceLabel}
              </span>
              <span className="rounded-full bg-brand-500/10 px-3 py-2 text-[11px] font-semibold text-brand-300">
                {formatEnumLabel(finalMode, 'Waiting for route confirmation')}
              </span>
            </div>
          </div>

          <div className="mt-5 grid gap-3 md:grid-cols-2">
            <ContactCard
              label="Donor Contact"
              name={foodData?.donorName}
              contact={foodData?.donorContact}
              accent={currentRole === 'DONOR' ? 'text-brand-200' : 'text-white'}
            />
            <ContactCard
              label="Organization Contact"
              name={foodData?.acceptedByName}
              contact={foodData?.acceptedByContact}
              accent={currentRole === 'ORGANIZATION' ? 'text-brand-200' : 'text-white'}
            />
          </div>

          <div className="mt-4 rounded-[22px] border border-brand-500/15 bg-brand-500/10 px-4 py-3">
            <p className="text-[10px] font-semibold uppercase tracking-[0.24em] text-brand-300">AI Route Guidance</p>
            <p className="mt-2 text-sm text-slate-100">{aiSuggestion}</p>
          </div>
        </div>
      </div>

      <div className="border-b border-slate-800/80 bg-white/[0.02] p-5">
        <div className="flex flex-wrap items-center justify-between gap-3">
          <p className="text-[11px] font-semibold uppercase tracking-[0.26em] text-slate-500">Route Decision</p>
          <span className="rounded-full bg-brand-500/10 px-3 py-1 text-[10px] font-semibold uppercase tracking-[0.2em] text-brand-300">
            Your choice: {formatEnumLabel(currentUserChoice, 'Not chosen yet')}
          </span>
        </div>

        {!finalMode ? (
          actionOptions.length > 0 ? (
            <div className="mt-5 grid gap-3 lg:grid-cols-2">
              {actionOptions.map((option) => (
                <button
                  key={option.mode}
                  type="button"
                  onClick={() => handleSelectMode(option.mode)}
                  disabled={loading}
                  className={`rounded-[22px] border px-4 py-4 text-left transition-all ${
                    currentUserChoice === option.mode
                      ? 'border-brand-500/30 bg-brand-500/12 text-white shadow-[0_12px_40px_rgba(16,185,129,0.08)]'
                      : 'border-slate-800/80 bg-slate-950/80 text-slate-200 hover:border-slate-700 hover:bg-slate-900'
                  }`}
                >
                  <p className="text-sm font-semibold">{option.title}</p>
                  <p className="mt-1 text-[11px] leading-5 text-slate-400">{option.description}</p>
                </button>
              ))}
            </div>
          ) : (
            <div className="mt-5 rounded-[22px] border border-slate-800/80 bg-slate-950/80 px-4 py-4 text-sm text-slate-400">
              {currentRole === 'ORGANIZATION'
                ? 'Waiting for the donor to confirm after reviewing the organization details.'
                : 'Choose the delivery plan you are comfortable with.'}
            </div>
          )
        ) : (
          <div className="mt-5 rounded-[22px] border border-brand-500/15 bg-brand-500/10 p-4">
            <p className="text-[11px] font-semibold uppercase tracking-[0.22em] text-brand-300">Route Confirmed</p>
            <p className="mt-2 text-sm leading-7 text-slate-100">
              {finalMode === 'DONOR_DELIVERY'
                ? 'The donor will deliver this donation to the organization.'
                : finalMode === 'ORG_PICKUP'
                  ? 'The organization will travel to the donor and pick up the donation.'
                  : `A nearby NGO should now be assigned to deliver this donation to the organization.`}
            </p>
          </div>
        )}

        {canAssignPartner ? (
          <div className="mt-5 space-y-3">
            <div className="flex flex-wrap items-center justify-between gap-3">
              <div>
                <p className="text-sm font-medium text-slate-200">Nearest NGO contacts</p>
                <p className="mt-1 text-xs text-slate-400">Review the strongest nearby NGO options and choose one contact route.</p>
              </div>
              <button type="button" onClick={handleLoadPartners} className="rounded-full border border-slate-700/80 bg-white/[0.04] px-4 py-2 text-[10px] font-semibold uppercase tracking-[0.2em] text-slate-200 transition-all hover:border-brand-500/20 hover:text-white">
                Refresh List
              </button>
            </div>

            {showNgoPicker ? (
              <div className="grid gap-3 md:grid-cols-2">
                {sortedNgos.length > 0 ? sortedNgos.map((ngo, index) => (
                  <button
                    key={ngo.id}
                    type="button"
                    onClick={() => handleAssignNgo(ngo.id)}
                    className="rounded-[22px] border border-slate-800/80 bg-slate-950/80 p-4 text-left transition-all hover:border-brand-500/20 hover:bg-slate-900"
                  >
                    <p className="text-sm font-semibold text-white">{index === 0 ? `Strongest NGO match: ${ngo.name}` : ngo.name}</p>
                    <p className="mt-1 text-xs text-slate-400">Contact: {safeText(ngo.contact, 'Not available')}</p>
                    <p className="mt-1 text-xs text-slate-400">Location: {safeText(ngo.location, 'Location unavailable')}</p>
                    <p className="mt-1 text-xs text-brand-300">{getDistanceLabel(calculateDistanceKm(foodData?.location, ngo.location))}</p>
                    <p className="mt-3 text-[10px] font-semibold uppercase tracking-[0.22em] text-slate-500">Select this NGO</p>
                  </button>
                )) : (
                  <div className="rounded-[22px] border border-slate-800/80 bg-slate-950/80 p-5 text-sm text-slate-400">
                    No nearby partners are available right now.
                  </div>
                )}
              </div>
            ) : null}
          </div>
        ) : null}
      </div>

      <div ref={scrollRef} className="max-h-[220px] overflow-y-auto bg-[linear-gradient(180deg,rgba(2,6,23,0.26),rgba(15,23,42,0.16))] p-4">
        {fetching && messageList.length === 0 ? (
          <div className="flex justify-center py-12">
            <Loader />
          </div>
        ) : messageList.length === 0 ? (
          <div className="py-12 text-center">
            <p className="text-sm text-slate-400">
              {normalizedStatus === 'DELIVERED'
                ? 'Delivery is complete. You can still share a thank-you note or final confirmation here.'
                : 'No messages yet. Share timing or pickup details here.'}
            </p>
          </div>
        ) : (
          <div className="space-y-3">
            {messageList.map((message) => (
              <MessageBubble
                key={message.id}
                message={message}
                ownMessage={message?.senderId === user?.userId}
                fallbackName={currentRole === 'DONOR' ? 'Organization' : 'Donor'}
              />
            ))}
          </div>
        )}
      </div>

      <form onSubmit={handleSend} className="border-t border-slate-800/80 bg-dark-950/80 p-3">
        <div className="flex gap-3">
          <input
            type="text"
            value={text}
            onChange={(event) => setText(event.target.value)}
            placeholder={normalizedStatus === 'DELIVERED' ? 'Share a thank-you note or final update' : 'Share a delivery update'}
            className="flex-1 rounded-2xl border border-slate-800/80 bg-slate-900 px-4 py-3 text-sm text-white outline-none transition-all placeholder:text-slate-600 focus:border-brand-500/40 focus:ring-2 focus:ring-brand-500/25"
            disabled={loading || !canSendMessage}
          />
          <button
            type="submit"
            disabled={loading || !text.trim() || !canSendMessage}
            className={`rounded-2xl px-5 py-3 text-xs font-semibold uppercase tracking-[0.22em] transition-all ${
              loading || !text.trim() || !canSendMessage
                ? 'cursor-not-allowed bg-slate-800 text-slate-500'
                : 'bg-brand-600 text-white shadow-lg shadow-brand-600/20 hover:bg-brand-500'
            }`}
          >
            {loading ? 'Sending' : normalizedStatus === 'DELIVERED' ? 'Send Thanks' : 'Send'}
          </button>
        </div>
      </form>
    </div>
  );
}
