import { useCallback, useEffect, useMemo, useState } from 'react';
import { Link, useNavigate, useParams } from 'react-router-dom';
import toast from 'react-hot-toast';
import ConfirmModal from '../components/ConfirmModal';
import Loader from '../components/Loader';
import ProgressBar from '../components/ProgressBar';
import { getAllFood, getMessages, updateFoodStatus } from '../services/api';
import { formatConditionLabel, formatDateTime, formatEnumLabel, safeText } from '../utils/workflow';

function StatCard({ label, value, accent = 'text-white' }) {
  return (
    <div className="rounded-[24px] border border-slate-800/80 bg-white/[0.035] p-4">
      <p className="text-[10px] font-semibold uppercase tracking-[0.22em] text-slate-500">{label}</p>
      <p className={`mt-2 text-sm font-medium leading-6 ${accent}`}>{value}</p>
    </div>
  );
}

export default function AdminDonationWorkspace() {
  const { donationId } = useParams();
  const navigate = useNavigate();
  const [items, setItems] = useState([]);
  const [messages, setMessages] = useState([]);
  const [loading, setLoading] = useState(true);
  const [dialog, setDialog] = useState(null);
  const [actionBusy, setActionBusy] = useState(false);

  const refreshPage = useCallback(async () => {
    try {
      const [foodResult, messageResult] = await Promise.all([
        getAllFood(),
        getMessages(donationId),
      ]);
      setItems(Array.isArray(foodResult?.data) ? foodResult.data : []);
      setMessages(Array.isArray(messageResult?.data) ? messageResult.data : []);
    } catch (err) {
      toast.error(err?.response?.data?.message || 'Failed to load donation oversight');
    } finally {
      setLoading(false);
    }
  }, [donationId]);

  useEffect(() => {
    refreshPage();
    const interval = setInterval(refreshPage, 4000);
    return () => clearInterval(interval);
  }, [refreshPage]);

  const donation = useMemo(
    () => items.find((item) => String(item?.id) === String(donationId)) || null,
    [items, donationId]
  );

  const selectedStatus = String(donation?.status || 'POSTED').toUpperCase().trim();

  const handleStatusUpdate = useCallback(async (status) => {
    if (!donation?.id) return;

    try {
      await updateFoodStatus(donation.id, status);
      await refreshPage();
      toast.success(`Admin updated status to ${formatEnumLabel(status)}`);
    } catch (err) {
      toast.error(err?.response?.data?.message || 'Status update failed');
      throw err;
    }
  }, [donation?.id, refreshPage]);

  if (loading) return <Loader size="lg" />;

  if (!donation) {
    return (
      <div className="glass-card rounded-[30px] p-12 text-center">
        <h1 className="text-2xl font-semibold text-white">Donation not found</h1>
        <p className="mt-3 text-slate-400">This donation may have been removed or the link is outdated.</p>
        <button type="button" onClick={() => navigate('/dashboard')} className="btn-primary mt-6 px-6 py-3">
          Back to Admin Center
        </button>
      </div>
    );
  }

  return (
    <div className="space-y-8 animate-fade-in">
      <section className="overflow-hidden rounded-[34px] border border-slate-800/80 bg-[radial-gradient(circle_at_top_left,_rgba(16,185,129,0.18),_transparent_28%),linear-gradient(180deg,rgba(15,23,42,0.97),rgba(3,7,18,0.98))] p-7 shadow-[0_24px_90px_rgba(3,8,20,0.45)] sm:p-9">
        <div className="flex flex-col gap-6 xl:flex-row xl:items-end xl:justify-between">
          <div className="max-w-4xl">
            <Link to="/dashboard" className="inline-flex items-center gap-2 text-[11px] font-semibold uppercase tracking-[0.25em] text-slate-400 transition-colors hover:text-brand-300">
              Back to Admin Center
            </Link>
            <p className="mt-5 text-[11px] font-semibold uppercase tracking-[0.34em] text-brand-300">Donation Oversight</p>
            <h1 className="mt-3 text-3xl font-semibold tracking-tight text-white sm:text-[42px]">
              {safeText(donation.title, 'Donation Record')}
            </h1>
            <p className="mt-4 max-w-3xl text-[15px] leading-7 text-slate-300">
              Full administrative visibility into donor, organization, delivery progress, and the complete conversation trail.
            </p>
          </div>

          <div className="grid gap-3 sm:grid-cols-3">
            <StatCard label="Status" value={formatEnumLabel(selectedStatus, 'Posted')} />
            <StatCard label="Delivery Path" value={formatEnumLabel(donation.deliveryMode, 'Pending')} />
            <StatCard label="AI Match" value={safeText(donation.aiScore, 'N/A')} accent="text-brand-200" />
          </div>
        </div>
      </section>

      <div className="grid gap-8 xl:grid-cols-[1.08fr_0.92fr]">
        <div className="space-y-6">
          <div className="glass-card rounded-[30px] border border-slate-800/80 p-6 sm:p-7">
            <div className="flex flex-wrap items-start justify-between gap-4">
              <div>
                <p className="text-[11px] font-semibold uppercase tracking-[0.26em] text-slate-500">Process Summary</p>
                <h2 className="mt-2 text-[28px] font-semibold tracking-tight text-white">Complete donation record</h2>
              </div>
            </div>

            <div className="mt-6 grid auto-rows-fr gap-3 sm:grid-cols-2 xl:grid-cols-3">
              <StatCard label="Donor" value={safeText(donation.donorName, 'Unknown donor')} />
              <StatCard label="Donor Contact" value={safeText(donation.donorContact, 'Not available')} />
              <StatCard label="Organization" value={safeText(donation.acceptedByName, 'Awaiting organization')} />
              <StatCard label="Organization Contact" value={safeText(donation.acceptedByContact, 'Not available')} />
              <StatCard label="Condition" value={formatConditionLabel(donation.condition, 'Not specified')} />
              <StatCard label="Quantity" value={safeText(donation.quantity, '0')} />
              <StatCard label="Expiry" value={formatDateTime(donation.expiryTime)} />
              <StatCard label="Donor Choice" value={formatEnumLabel(donation.donorDeliveryPreference, 'Pending')} />
              <StatCard label="Organization Choice" value={formatEnumLabel(donation.organizationDeliveryPreference, 'Pending')} />
              <div className="rounded-[24px] border border-slate-800/80 bg-white/[0.035] p-4 sm:col-span-2 xl:col-span-3">
                <p className="text-[10px] font-semibold uppercase tracking-[0.22em] text-slate-500">Location</p>
                <p className="mt-2 text-sm font-medium leading-6 text-white">{safeText(donation.location, 'Not shared')}</p>
              </div>
            </div>

            <div className="mt-6">
              <ProgressBar status={selectedStatus} deliveryMode={donation?.deliveryMode} />
            </div>

            <div className="mt-6 flex flex-wrap gap-3">
              {selectedStatus === 'ACCEPTED' || selectedStatus === 'PENDING_NGO' ? (
                <button
                  type="button"
                  onClick={() => setDialog({
                    status: 'PICKUP_STARTED',
                    title: 'Confirm Pickup',
                    message: 'Administrative override will move this donation to pickup confirmed.',
                    confirmLabel: 'Confirm Pickup',
                  })}
                  className="rounded-full bg-brand-600 px-5 py-3 text-[11px] font-semibold uppercase tracking-[0.2em] text-white transition-all hover:bg-brand-500"
                >
                  Confirm Pickup
                </button>
              ) : null}
              {selectedStatus === 'PICKUP_STARTED' ? (
                <button
                  type="button"
                  onClick={() => setDialog({
                    status: 'DELIVERED',
                    title: 'Confirm Completion',
                    message: 'Administrative completion will close this donation as delivered.',
                    confirmLabel: 'Mark Completed',
                  })}
                  className="rounded-full bg-emerald-600 px-5 py-3 text-[11px] font-semibold uppercase tracking-[0.2em] text-white transition-all hover:bg-emerald-500"
                >
                  Mark Completed
                </button>
              ) : null}
            </div>
          </div>

          <div className="glass-card rounded-[30px] border border-slate-800/80 p-6 sm:p-7">
            <p className="text-[11px] font-semibold uppercase tracking-[0.26em] text-slate-500">Conversation Timeline</p>
            <div className="mt-5 space-y-3">
              {messages.length > 0 ? messages.map((message) => (
                <div key={message.id} className={`rounded-[22px] border px-4 py-3 ${
                  message?.isSystem
                    ? 'border-slate-800/80 bg-slate-950/90'
                    : 'border-slate-800/80 bg-white/[0.03]'
                }`}>
                  <p className="text-[10px] font-semibold uppercase tracking-[0.22em] text-slate-500">
                    {message?.isSystem ? 'System' : safeText(message?.senderName, 'Participant')}
                  </p>
                  <p className="mt-2 text-sm leading-7 text-slate-100">{message?.content}</p>
                  <p className="mt-2 text-[10px] text-slate-500">
                    {message?.timestamp ? new Date(message.timestamp).toLocaleString() : 'Time unavailable'}
                  </p>
                </div>
              )) : (
                <div className="rounded-[22px] border border-slate-800/80 bg-white/[0.03] px-4 py-6 text-sm text-slate-400">
                  No conversation data is available for this donation yet.
                </div>
              )}
            </div>
          </div>
        </div>

        <div className="space-y-6">
          <div className="glass-card rounded-[30px] border border-slate-800/80 p-6 sm:p-7">
            <p className="text-[11px] font-semibold uppercase tracking-[0.26em] text-slate-500">Administrative Notes</p>
            <div className="mt-5 grid gap-3">
              <StatCard label="Created" value={formatDateTime(donation.createdAt)} />
              <StatCard label="Route Partner" value={safeText(donation.ngoName, 'Not assigned')} />
              <StatCard label="Address" value={safeText(donation.acceptedByAddress, 'Not available')} />
            </div>
          </div>
        </div>
      </div>

      <ConfirmModal
        open={Boolean(dialog)}
        title={dialog?.title}
        message={dialog?.message}
        confirmLabel={dialog?.confirmLabel}
        busy={actionBusy}
        onConfirm={async () => {
          if (!dialog?.status) return;
          setActionBusy(true);
          try {
            await handleStatusUpdate(dialog.status);
            setDialog(null);
          } finally {
            setActionBusy(false);
          }
        }}
        onClose={() => {
          if (!actionBusy) setDialog(null);
        }}
      />
    </div>
  );
}
