import { useCallback, useEffect, useMemo, useState } from 'react';
import { Link, useNavigate, useParams } from 'react-router-dom';
import toast from 'react-hot-toast';
import ConfirmModal from '../components/ConfirmModal';
import DeliveryChatPanel from '../components/DeliveryChatPanel';
import Loader from '../components/Loader';
import MapView from '../components/MapView';
import ProgressBar from '../components/ProgressBar';
import { useAuth } from '../context/AuthContext';
import { getAllFood, rejectFood, selectDeliveryMode, updateFoodStatus } from '../services/api';
import {
  buildDeliveryToast,
  formatConditionLabel,
  formatDateTime,
  formatEnumLabel,
  getAgreementStatus,
  getPartnerLabel,
  isPartnerAssistedMode,
  safeText,
} from '../utils/workflow';
import { calculateDistanceKm, ensureArray, getDistanceLabel } from '../utils/orgDashboard';

function SnapshotCard({ label, value, accent = 'text-white' }) {
  return (
    <div className="flex h-full flex-col rounded-[24px] border border-slate-800/80 bg-white/[0.035] p-4">
      <p className="text-[10px] font-semibold uppercase tracking-[0.22em] text-slate-500">{label}</p>
      <p className={`mt-2 flex-1 text-sm font-medium leading-6 ${accent}`}>{value}</p>
    </div>
  );
}

export default function OrgDonationWorkspace() {
  const { donationId } = useParams();
  const navigate = useNavigate();
  const { user } = useAuth();
  const [loading, setLoading] = useState(true);
  const [items, setItems] = useState([]);
  const [dialog, setDialog] = useState(null);
  const [actionBusy, setActionBusy] = useState(false);

  const orgUserId = user?.userId ?? user?.id ?? null;
  const orgLocation = safeText(user?.location, '');

  const refreshWorkspace = useCallback(async () => {
    try {
      const { data } = await getAllFood();
      const safeItems = ensureArray(data)
        .filter((item) => item?.acceptedById === orgUserId);
      setItems(safeItems);
    } catch (err) {
      toast.error(err?.response?.data?.message || 'Failed to refresh this request');
    } finally {
      setLoading(false);
    }
  }, [orgUserId]);

  useEffect(() => {
    refreshWorkspace();
    const interval = setInterval(refreshWorkspace, 4000);
    return () => clearInterval(interval);
  }, [refreshWorkspace]);

  const donation = useMemo(
    () => items.find((item) => String(item?.id) === String(donationId)) || null,
    [donationId, items]
  );

  const selectedStatus = String(donation?.status || 'POSTED').toUpperCase().trim();
  const deliveryLocked = Boolean(donation?.deliveryMode);
  const distanceKm = calculateDistanceKm(orgLocation, donation?.location);
  const distanceLabel = getDistanceLabel(distanceKm);

  const handleSelectDelivery = useCallback(async (mode) => {
    if (!donation?.id) return;

    try {
      const { data } = await selectDeliveryMode(donation.id, mode);
      setItems((current) => current.map((item) => (item?.id === data?.id ? data : item)));
      toast.success(buildDeliveryToast(data, mode));
      return data;
    } catch (err) {
      toast.error(err?.response?.data?.message || 'Failed to share delivery choice');
      throw err;
    }
  }, [donation?.id]);

  const performStatusUpdate = useCallback(async (status) => {
    if (!donation?.id) return;

    try {
      const { data } = await updateFoodStatus(donation.id, status);
      setItems((current) => current.map((item) => (item?.id === data?.id ? data : item)));
      toast.success(`Status updated to ${formatEnumLabel(status)}`);
      return data;
    } catch (err) {
      toast.error(err?.response?.data?.message || 'Update failed');
      throw err;
    }
  }, [donation?.id]);

  const handleRejectRequest = useCallback(async () => {
    if (!donation?.id) return;

    try {
      await rejectFood(donation.id);
      toast.success('Donation rejected and released');
      navigate('/dashboard');
    } catch (err) {
      toast.error(err?.response?.data?.message || 'Reject failed');
      throw err;
    }
  }, [donation?.id, navigate]);

  const closeDialog = useCallback(() => {
    if (!actionBusy) setDialog(null);
  }, [actionBusy]);

  const handleConfirmDialog = useCallback(async () => {
    if (!dialog) return;

    setActionBusy(true);
    try {
      if (dialog.type === 'reject') {
        await handleRejectRequest();
      }
      if (dialog.type === 'status') {
        await performStatusUpdate(dialog.status);
      }
      setDialog(null);
    } finally {
      setActionBusy(false);
    }
  }, [dialog, handleRejectRequest, performStatusUpdate]);

  if (loading) return <Loader size="lg" />;

  if (!donation) {
    return (
      <div className="glass-card rounded-[30px] p-12 text-center">
        <h1 className="text-2xl font-semibold text-white">Request not found</h1>
        <p className="mt-3 text-slate-400">
          This request may no longer belong to your organization or the link is outdated.
        </p>
        <button type="button" onClick={() => navigate('/dashboard')} className="btn-primary mt-6 px-6 py-3">
          Back to Hub
        </button>
      </div>
    );
  }

  return (
    <div className="space-y-8 animate-fade-in">
      <section className="overflow-hidden rounded-[36px] border border-slate-800/80 bg-[radial-gradient(circle_at_top_left,_rgba(16,185,129,0.16),_transparent_30%),radial-gradient(circle_at_bottom_right,_rgba(59,130,246,0.10),_transparent_28%),linear-gradient(180deg,rgba(15,23,42,0.96),rgba(5,11,22,0.98))] p-7 shadow-[0_26px_90px_rgba(3,8,20,0.48)] sm:p-9">
        <div className="flex flex-col gap-6 xl:flex-row xl:items-end xl:justify-between">
          <div className="max-w-4xl">
            <Link to="/dashboard" className="inline-flex items-center gap-2 text-[11px] font-semibold uppercase tracking-[0.25em] text-slate-400 transition-colors hover:text-brand-300">
              Back to Organization Hub
            </Link>
            <p className="mt-5 text-[11px] font-semibold uppercase tracking-[0.34em] text-brand-300">Request Record</p>
            <h1 className="mt-3 text-3xl font-semibold tracking-tight text-white sm:text-[42px]">
              {safeText(donation.title, 'Accepted donation')}
            </h1>
            <p className="mt-4 max-w-3xl text-[15px] leading-7 text-slate-300">
              {getAgreementStatus(donation)}
            </p>
          </div>

          <div className="grid gap-3 sm:grid-cols-3">
            <div className="rounded-[24px] border border-slate-800/80 bg-white/[0.04] px-5 py-4">
              <p className="text-[10px] font-semibold uppercase tracking-[0.22em] text-slate-500">Status</p>
              <p className="mt-2 text-xl font-semibold text-white">{formatEnumLabel(selectedStatus, 'Posted')}</p>
            </div>
            <div className="rounded-[24px] border border-slate-800/80 bg-white/[0.04] px-5 py-4">
              <p className="text-[10px] font-semibold uppercase tracking-[0.22em] text-slate-500">Distance</p>
              <p className="mt-2 text-xl font-semibold text-white">{distanceLabel}</p>
            </div>
            <div className="rounded-[24px] border border-slate-800/80 bg-white/[0.04] px-5 py-4">
              <p className="text-[10px] font-semibold uppercase tracking-[0.22em] text-slate-500">Delivery</p>
              <p className="mt-2 text-xl font-semibold text-white">{formatEnumLabel(donation.deliveryMode, 'Pending')}</p>
            </div>
          </div>
        </div>

        {(selectedStatus === 'ACCEPTED' || selectedStatus === 'PENDING_NGO') ? (
          <div className="mt-6">
            <button
              type="button"
              onClick={() => setDialog({
                type: 'reject',
                title: 'Reject Donation',
                message: 'This will release the donation back to posted state so another organization can take it.',
                confirmLabel: 'Reject Donation',
                tone: 'danger',
              })}
              className="rounded-full border border-rose-500/20 bg-rose-500/10 px-5 py-3 text-[11px] font-semibold uppercase tracking-[0.2em] text-rose-100 transition-all hover:bg-rose-500/20"
            >
              Reject Donation
            </button>
          </div>
        ) : null}
      </section>

      <div className="grid gap-8 xl:grid-cols-[1.06fr_0.94fr]">
        <div className="space-y-6">
          <div className="glass-card rounded-[30px] border border-slate-800/80 p-6 sm:p-7">
            <div className="flex flex-wrap items-start justify-between gap-4">
              <div>
                <p className="text-[11px] font-semibold uppercase tracking-[0.26em] text-slate-500">Donation Details</p>
                <h2 className="mt-2 text-[28px] font-semibold tracking-tight text-white">Everything your team needs</h2>
              </div>
              <span className="rounded-full border border-brand-500/20 bg-brand-500/10 px-4 py-2 text-[11px] font-semibold uppercase tracking-[0.22em] text-brand-300">
                {formatEnumLabel(donation.category, 'Donation')}
              </span>
            </div>

            <div className="mt-6 grid auto-rows-fr gap-3 sm:grid-cols-2 xl:grid-cols-3">
              <SnapshotCard label="Item Type" value={safeText(donation.type, 'General item')} />
              <SnapshotCard label="Quantity" value={safeText(donation.quantity, '0')} />
              <SnapshotCard label="Condition" value={formatConditionLabel(donation.condition, 'Not specified')} />
              <SnapshotCard label="Expiry" value={formatDateTime(donation.expiryTime)} />
              <SnapshotCard label="Donor" value={safeText(donation.donorName, 'Unknown donor')} />
              <SnapshotCard label="Contact" value={safeText(donation.donorContact, 'Not available')} />
              <div className="rounded-[24px] border border-slate-800/80 bg-white/[0.035] p-4 sm:col-span-2 xl:col-span-3">
                <p className="text-[10px] font-semibold uppercase tracking-[0.22em] text-slate-500">Pickup Location</p>
                <p className="mt-2 text-sm font-medium leading-6 text-white">{safeText(donation.location, 'Not shared')}</p>
              </div>
            </div>

            <div className="mt-6">
              <ProgressBar status={selectedStatus} deliveryMode={donation?.deliveryMode} />
            </div>

            {deliveryLocked && selectedStatus !== 'DELIVERED' ? (
              <div className="mt-6 flex flex-wrap gap-3">
                {selectedStatus === 'ACCEPTED' ? (
                  <div className="rounded-2xl border border-sky-500/20 bg-sky-500/10 px-4 py-3 text-xs font-medium text-sky-100">
                    Waiting for the donor to confirm that pickup has happened.
                  </div>
                ) : null}
                {selectedStatus === 'PICKUP_STARTED' ? (
                  <button
                    type="button"
                    onClick={() => setDialog({
                      type: 'status',
                      status: 'DELIVERED',
                      title: 'Confirm Delivery',
                      message: 'Mark this only after your organization has received the donation completely.',
                      confirmLabel: 'Mark Delivered',
                    })}
                    className="rounded-2xl bg-green-600 px-5 py-3 text-xs font-semibold uppercase tracking-[0.2em] text-white transition-all hover:bg-green-500"
                  >
                    Mark Delivered
                  </button>
                ) : null}
                {selectedStatus === 'PENDING_NGO' ? (
                  <div className="rounded-2xl border border-amber-500/20 bg-amber-500/10 px-4 py-3 text-xs font-medium text-amber-200">
                    {isPartnerAssistedMode(donation?.deliveryMode)
                      ? `Pickup will start after the ${getPartnerLabel(donation.deliveryMode)} is assigned.`
                      : 'Pickup is waiting for partner assignment.'}
                  </div>
                ) : null}
              </div>
            ) : null}
          </div>

          <div className="overflow-hidden rounded-[30px]">
            <DeliveryChatPanel
              foodId={donation.id}
              status={selectedStatus}
              foodData={donation}
              onSelectDelivery={handleSelectDelivery}
              onWorkflowUpdate={refreshWorkspace}
            />
          </div>
        </div>

        <div className="space-y-6">
          <div className="glass-card rounded-[30px] border border-slate-800/80 p-6 sm:p-7">
            <p className="text-[11px] font-semibold uppercase tracking-[0.26em] text-slate-500">Quick Snapshot</p>
            <div className="mt-5 grid auto-rows-fr gap-3">
              <SnapshotCard label="Donor" value={safeText(donation.donorName, 'Unknown donor')} accent="text-brand-200" />
              <SnapshotCard label="Distance" value={distanceLabel} />
              <SnapshotCard label="Selected Path" value={formatEnumLabel(donation.deliveryMode, 'Pending')} />
              <SnapshotCard label="Partner" value={safeText(donation.ngoName, 'Not assigned yet')} />
            </div>
          </div>

          <MapView
            donorLoc={safeText(donation.location, '')}
            orgLoc={orgLocation}
            donorName={safeText(donation.donorName, 'Donor')}
            orgName={safeText(user?.orgName || user?.name, 'Organization')}
          />
        </div>
      </div>

      <ConfirmModal
        open={Boolean(dialog)}
        title={dialog?.title}
        message={dialog?.message}
        confirmLabel={dialog?.confirmLabel}
        tone={dialog?.tone}
        busy={actionBusy}
        onConfirm={handleConfirmDialog}
        onClose={closeDialog}
      />
    </div>
  );
}
