import { useCallback, useEffect, useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import Loader from '../components/Loader';
import { getAdminStats, getAllFood, getOrganizations, verifyOrganization } from '../services/api';
import { formatEnumLabel, safeText } from '../utils/workflow';

function StatTile({ label, value, accent = 'default' }) {
  const accentClass = {
    default: 'border-slate-800/80 bg-white/[0.04]',
    brand: 'border-brand-500/20 bg-brand-500/10',
    success: 'border-emerald-500/20 bg-emerald-500/10',
  };

  return (
    <div className={`rounded-[24px] border px-5 py-4 ${accentClass[accent] || accentClass.default}`}>
      <p className="text-[10px] font-semibold uppercase tracking-[0.26em] text-slate-500">{label}</p>
      <p className="mt-3 text-3xl font-semibold text-white">{value}</p>
    </div>
  );
}

export default function AdminDashboardPro() {
  const navigate = useNavigate();
  const [stats, setStats] = useState(null);
  const [orgs, setOrgs] = useState([]);
  const [donations, setDonations] = useState([]);
  const [loading, setLoading] = useState(true);

  const refreshDashboard = useCallback(async () => {
    try {
      const [statsResult, orgResult, donationResult] = await Promise.all([
        getAdminStats(),
        getOrganizations(),
        getAllFood(),
      ]);
      setStats(statsResult.data);
      setOrgs(Array.isArray(orgResult.data) ? orgResult.data : []);
      setDonations(Array.isArray(donationResult.data) ? donationResult.data : []);
    } catch (err) {
      toast.error(err?.response?.data?.message || 'Failed to load admin data');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    refreshDashboard();
  }, [refreshDashboard]);

  const handleVerify = async (id) => {
    try {
      await verifyOrganization(id);
      await refreshDashboard();
      toast.success('Organization approved');
    } catch (err) {
      toast.error(err?.response?.data?.message || 'Verification failed');
    }
  };

  const sortedDonations = useMemo(
    () => [...donations].sort((left, right) => Number(right?.id ?? 0) - Number(left?.id ?? 0)),
    [donations]
  );

  if (loading) return <Loader size="lg" />;

  return (
    <div className="space-y-8 animate-fade-in">
      <section className="overflow-hidden rounded-[36px] border border-slate-800/80 bg-[radial-gradient(circle_at_top_left,_rgba(59,130,246,0.14),_transparent_28%),radial-gradient(circle_at_bottom_right,_rgba(16,185,129,0.10),_transparent_24%),linear-gradient(180deg,rgba(15,23,42,0.96),rgba(5,11,22,0.98))] p-7 shadow-[0_26px_90px_rgba(3,8,20,0.48)] sm:p-9">
        <div className="flex flex-col gap-8 xl:flex-row xl:items-end xl:justify-between">
          <div className="max-w-3xl">
            <p className="text-[11px] font-semibold uppercase tracking-[0.34em] text-brand-300">Admin Center</p>
            <h1 className="mt-4 text-3xl font-semibold tracking-tight text-white sm:text-[42px]">
              Full platform oversight with professional control.
            </h1>
            <p className="mt-4 text-[15px] leading-7 text-slate-300">
              Inspect every organization, review every donation process, and step into any active record directly from here.
            </p>
          </div>

          <div className="grid grid-cols-2 gap-3 sm:grid-cols-4 xl:min-w-[430px]">
            <StatTile label="Organizations" value={stats?.totalOrganizations || 0} accent="brand" />
            <StatTile label="Verified" value={stats?.verifiedOrganizations || 0} accent="success" />
            <StatTile label="Pending" value={stats?.pendingVerification || 0} />
            <StatTile label="Donations" value={donations.length} />
          </div>
        </div>
      </section>

      <div className="grid gap-8 xl:grid-cols-[0.96fr_1.04fr]">
        <section className="glass-card rounded-[30px] border border-slate-800/80 p-6 sm:p-7">
          <div>
            <h2 className="text-[28px] font-semibold tracking-tight text-white">Organization Records</h2>
            <p className="mt-1 text-sm text-slate-400">Click any organization to inspect identity, verification, and accepted donations.</p>
          </div>

          <div className="mt-6 space-y-3">
            {orgs.length > 0 ? orgs.map((org) => (
              <div
                key={org.id}
                role="button"
                tabIndex={0}
                onClick={() => navigate(`/dashboard/admin/organizations/${org.id}`)}
                onKeyDown={(event) => {
                  if (event.key === 'Enter' || event.key === ' ') {
                    event.preventDefault();
                    navigate(`/dashboard/admin/organizations/${org.id}`);
                  }
                }}
                className="cursor-pointer rounded-[24px] border border-slate-800/80 bg-white/[0.03] p-4 transition-all hover:border-brand-500/20 hover:bg-white/[0.045]"
              >
                <div className="flex items-start justify-between gap-3">
                  <div>
                    <p className="text-sm font-semibold text-white">{safeText(org.orgName || org.name, 'Organization')}</p>
                    <p className="mt-1 text-xs text-slate-400">{safeText(org.email, 'Email unavailable')}</p>
                    <p className="mt-1 text-xs text-slate-500">{safeText(org.location, 'Location unavailable')}</p>
                  </div>
                  <div className="flex flex-col items-end gap-2">
                    <span className={`rounded-full px-3 py-1 text-[10px] font-semibold uppercase tracking-[0.2em] ${
                      org.verified
                        ? 'bg-emerald-500/10 text-emerald-200'
                        : 'bg-amber-500/10 text-amber-200'
                    }`}>
                      {org.verified ? 'Verified' : 'Pending'}
                    </span>
                    {!org.verified ? (
                      <button
                        type="button"
                        onClick={(event) => {
                          event.stopPropagation();
                          handleVerify(org.id);
                        }}
                        className="rounded-full bg-brand-600 px-4 py-2 text-[10px] font-semibold uppercase tracking-[0.2em] text-white transition-all hover:bg-brand-500"
                      >
                        Approve
                      </button>
                    ) : null}
                  </div>
                </div>
              </div>
            )) : (
              <div className="rounded-[24px] border border-slate-800/80 bg-white/[0.03] px-4 py-6 text-sm text-slate-400">
                No organizations are available right now.
              </div>
            )}
          </div>
        </section>

        <section className="glass-card rounded-[30px] border border-slate-800/80 p-6 sm:p-7">
          <div>
            <h2 className="text-[28px] font-semibold tracking-tight text-white">Donation Records</h2>
            <p className="mt-1 text-sm text-slate-400">Click any donation to inspect delivery progress, messages, and administrative controls.</p>
          </div>

          <div className="mt-6 space-y-3">
            {sortedDonations.length > 0 ? sortedDonations.map((donation) => (
              <button
                key={donation.id}
                type="button"
                onClick={() => navigate(`/dashboard/admin/donations/${donation.id}`)}
                className="w-full rounded-[24px] border border-slate-800/80 bg-white/[0.03] p-4 text-left transition-all hover:border-brand-500/20 hover:bg-white/[0.045]"
              >
                <div className="flex items-start justify-between gap-3">
                  <div>
                    <p className="text-sm font-semibold text-white">{safeText(donation.title, 'Donation record')}</p>
                    <p className="mt-1 text-xs text-slate-400">
                      {safeText(donation.donorName, 'Unknown donor')} to {safeText(donation.acceptedByName, 'Awaiting organization')}
                    </p>
                    <p className="mt-1 text-xs text-slate-500">{formatEnumLabel(donation.status, 'Posted')}</p>
                  </div>
                  <span className="rounded-full bg-brand-500/10 px-3 py-1 text-[10px] font-semibold uppercase tracking-[0.2em] text-brand-300">
                    Inspect
                  </span>
                </div>
              </button>
            )) : (
              <div className="rounded-[24px] border border-slate-800/80 bg-white/[0.03] px-4 py-6 text-sm text-slate-400">
                No donation records are available right now.
              </div>
            )}
          </div>
        </section>
      </div>
    </div>
  );
}
