import { useCallback, useEffect, useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import ConfirmModal from '../components/ConfirmModal';
import Loader from '../components/Loader';
import { useAuth } from '../context/AuthContext';
import { acceptFood, getAllFood, getRankedFood, rejectFood } from '../services/api';
import { formatConditionLabel, formatDateTime, formatEnumLabel, safeText } from '../utils/workflow';
import {
  calculateDistanceKm,
  dedupeById,
  describeScore,
  ensureArray,
  getDistanceLabel,
  sortOpportunities,
} from '../utils/orgDashboard';

function StatTile({ label, value, tone = 'default' }) {
  const toneClasses = {
    default: 'border-slate-800/80 bg-white/[0.045] text-white',
    success: 'border-emerald-400/20 bg-emerald-400/10 text-emerald-100',
    brand: 'border-brand-500/20 bg-brand-500/10 text-white',
  };

  return (
    <div className={`rounded-[24px] border px-5 py-4 shadow-[inset_0_1px_0_rgba(255,255,255,0.03)] ${toneClasses[tone] || toneClasses.default}`}>
      <p className="text-[10px] font-semibold uppercase tracking-[0.28em] text-slate-500">{label}</p>
      <p className="mt-3 text-3xl font-semibold tracking-tight">{value}</p>
    </div>
  );
}

function ActiveRequestCard({ item, onOpen }) {
  return (
    <button
      type="button"
      onClick={() => onOpen(item.id)}
      className="group w-full rounded-[28px] border border-slate-800/80 bg-[linear-gradient(180deg,rgba(255,255,255,0.04),rgba(255,255,255,0.02))] p-5 text-left transition-all hover:-translate-y-1 hover:border-brand-500/20"
    >
      <div className="flex flex-wrap items-start justify-between gap-4">
        <div className="space-y-3">
          <div className="flex flex-wrap items-center gap-2">
            <span className="rounded-full border border-brand-500/20 bg-brand-500/10 px-3 py-1 text-[10px] font-semibold uppercase tracking-[0.22em] text-brand-300">
              Accepted
            </span>
            <span className="rounded-full border border-slate-700/70 bg-white/[0.05] px-3 py-1 text-[10px] font-semibold uppercase tracking-[0.22em] text-slate-200">
              {formatEnumLabel(item.status, 'Posted')}
            </span>
          </div>

          <div>
            <h3 className="text-[24px] font-semibold tracking-tight text-white">
              {safeText(item.title, 'Accepted donation')}
            </h3>
            <p className="mt-2 text-sm font-medium text-slate-400">
              {safeText(item.donorName, 'Unknown donor')} | {safeText(item.type, 'Food item')} | Qty {safeText(item.quantity, '0')}
            </p>
            <p className="mt-1 text-xs text-slate-500">
              Condition: {formatConditionLabel(item.condition, 'Not specified')}
            </p>
          </div>
        </div>

      </div>
    </button>
  );
}

function OpportunityCard({ item, orgLocation, onAccept, onReject, disabled, order }) {
  const distanceKm = calculateDistanceKm(orgLocation, item.location);
  const distanceLabel = getDistanceLabel(distanceKm);

  return (
    <div className={`group flex h-full flex-col overflow-hidden rounded-[30px] border p-5 transition-all ${
      item.recommended
        ? 'border-brand-500/25 bg-[linear-gradient(180deg,rgba(16,185,129,0.08),rgba(255,255,255,0.025))] shadow-[0_16px_60px_rgba(16,185,129,0.10)]'
        : 'border-slate-800/80 bg-[linear-gradient(180deg,rgba(255,255,255,0.04),rgba(255,255,255,0.02))] hover:border-brand-500/18'
    }`}>
      <div className="flex items-start justify-between gap-3">
        <div className="flex flex-wrap items-center gap-2">
          <span className="rounded-full border border-slate-700/70 bg-white/[0.04] px-3 py-1 text-[10px] font-semibold uppercase tracking-[0.22em] text-slate-300">
            #{order}
          </span>
          <span className="rounded-full border border-slate-700/70 bg-white/[0.05] px-3 py-1 text-[10px] font-semibold uppercase tracking-[0.22em] text-slate-200">
            {formatEnumLabel(item.category, 'Donation')}
          </span>
          {item.recommended ? (
            <span className="rounded-full border border-brand-500/20 bg-brand-500/10 px-3 py-1 text-[10px] font-semibold uppercase tracking-[0.22em] text-brand-300">
              Top Match
            </span>
          ) : null}
        </div>
        <div className="text-right">
          <p className="text-[10px] font-semibold uppercase tracking-[0.24em] text-slate-500">Distance</p>
          <p className="mt-2 text-lg font-semibold text-white">{distanceKm == null ? '--' : `${distanceKm} km`}</p>
        </div>
      </div>

      <div className="mt-5">
        <h3 className="text-[24px] font-semibold tracking-tight text-white">
          {safeText(item.title, safeText(item.foodType || item.category, 'Donation'))}
        </h3>
        <p className="mt-2 text-sm text-slate-400">
          {safeText(item.donorName, 'Unknown donor')} | {safeText(item.type, 'Food item')}
        </p>
        <p className="mt-1 text-xs text-slate-500">
          Condition: {formatConditionLabel(item.condition, 'Not specified')}
        </p>
      </div>

      <div className="mt-6 grid gap-3 sm:grid-cols-2">
        <div className="rounded-[22px] border border-slate-800/80 bg-white/[0.03] px-4 py-4">
          <p className="text-[10px] font-semibold uppercase tracking-[0.22em] text-slate-500">Quantity</p>
          <p className="mt-2 text-sm font-medium text-white">{safeText(item.quantity, '0')}</p>
        </div>
        <div className="rounded-[22px] border border-slate-800/80 bg-white/[0.03] px-4 py-4">
          <p className="text-[10px] font-semibold uppercase tracking-[0.22em] text-slate-500">Expiry</p>
          <p className="mt-2 text-sm font-medium text-white">{formatDateTime(item.expiryTime)}</p>
        </div>
        <div className="rounded-[22px] border border-slate-800/80 bg-white/[0.03] px-4 py-4 sm:col-span-2">
          <p className="text-[10px] font-semibold uppercase tracking-[0.22em] text-slate-500">Location</p>
          <p className="mt-2 text-sm font-medium text-white">{distanceLabel}</p>
        </div>
      </div>

      <div className="mt-auto pt-5 flex items-center justify-between gap-3">
        <div>
          <p className="text-xs font-medium text-brand-300">{describeScore(item.aiScore)}</p>
          <p className="mt-1 text-xs text-slate-500">AI Match Score {item.aiScore ?? '--'}</p>
        </div>
        <div className="flex flex-wrap gap-2">
          <button
            type="button"
            onClick={() => onReject(item.id)}
            disabled={disabled}
            className={`rounded-full px-5 py-3 text-[11px] font-semibold uppercase tracking-[0.2em] transition-all ${
              disabled
                ? 'cursor-not-allowed border border-slate-700 bg-slate-800 text-slate-500'
                : 'border border-rose-500/20 bg-rose-500/10 text-rose-100 hover:bg-rose-500/20'
            }`}
          >
            Reject
          </button>
          <button
            type="button"
            onClick={() => onAccept(item.id)}
            disabled={disabled}
            className={`rounded-full px-5 py-3 text-[11px] font-semibold uppercase tracking-[0.2em] transition-all ${
              disabled
                ? 'cursor-not-allowed border border-slate-700 bg-slate-800 text-slate-500'
                : 'bg-brand-500 text-white shadow-lg shadow-brand-500/20 hover:bg-brand-600'
            }`}
          >
            Accept
          </button>
        </div>
      </div>
    </div>
  );
}

export default function OrgDashboardOverview() {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [available, setAvailable] = useState([]);
  const [myItems, setMyItems] = useState([]);
  const [rejectedIds, setRejectedIds] = useState([]);
  const [loading, setLoading] = useState(true);
  const [dialog, setDialog] = useState(null);
  const [actionBusy, setActionBusy] = useState(false);

  const orgUserId = user?.userId ?? user?.id ?? null;
  const isVerified = Boolean(user?.verified);
  const orgLocation = safeText(user?.location, '');

  const refreshDashboard = useCallback(async () => {
    try {
      const [rankedResult, allResult] = await Promise.allSettled([
        getRankedFood(),
        getAllFood(),
      ]);

      const allItems = allResult.status === 'fulfilled'
        ? ensureArray(allResult.value?.data)
        : [];

      const rankedItems = rankedResult.status === 'fulfilled'
        ? ensureArray(rankedResult.value?.data)
        : allItems.filter((item) => item?.status === 'POSTED');

      const acceptedItems = orgUserId == null
        ? []
        : allItems.filter((item) => item?.acceptedById === orgUserId);

      setAvailable(
        dedupeById(rankedItems)
          .filter((item) => item?.id != null)
          .filter((item) => item?.status === 'POSTED' || item?.status == null)
          .filter((item) => !rejectedIds.includes(item.id))
      );
      setMyItems(dedupeById(acceptedItems).filter((item) => item?.id != null));

      if (rankedResult.status === 'rejected' && allResult.status === 'rejected') {
        throw rankedResult.reason ?? allResult.reason;
      }
    } catch (err) {
      toast.error(err?.response?.data?.message || 'Failed to load donation listings');
    } finally {
      setLoading(false);
    }
  }, [orgUserId, rejectedIds]);

  useEffect(() => {
    refreshDashboard();
    const interval = setInterval(refreshDashboard, 4000);
    return () => clearInterval(interval);
  }, [refreshDashboard]);

  const handleAccept = async (id) => {
    try {
      const { data } = await acceptFood(id);
      setRejectedIds((current) => current.filter((itemId) => itemId !== id));
      setAvailable((current) => current.filter((item) => item?.id !== id));
      setMyItems((current) => {
        const next = [data, ...current.filter((item) => item?.id !== id)];
        return next;
      });
      await refreshDashboard();
      toast.success('Donation accepted');
    } catch (err) {
      toast.error(err?.response?.data?.message || 'Acceptance failed');
      throw err;
    }
  };

  const handleReject = async (id) => {
    try {
      await rejectFood(id);
      setRejectedIds((current) => current.includes(id) ? current : [...current, id]);
      setAvailable((current) => current.filter((item) => item?.id !== id));
      await refreshDashboard();
      toast.success('Donation rejected for your organization');
    } catch (err) {
      toast.error(err?.response?.data?.message || 'Reject failed');
      throw err;
    }
  };

  const closeDialog = () => {
    if (!actionBusy) setDialog(null);
  };

  const handleConfirmDialog = async () => {
    if (!dialog?.id) return;

    setActionBusy(true);
    try {
      if (dialog.type === 'accept') {
        await handleAccept(dialog.id);
      }
      if (dialog.type === 'reject') {
        await handleReject(dialog.id);
      }
      setDialog(null);
    } finally {
      setActionBusy(false);
    }
  };

  const stats = useMemo(() => ({
    requests: myItems.length,
    opportunities: available.length,
    recommended: available.filter((item) => item?.recommended).length,
  }), [available, myItems.length]);

  const sortedAvailable = useMemo(
    () => sortOpportunities(available, orgLocation),
    [available, orgLocation]
  );

  if (loading) return <Loader size="lg" />;

  return (
    <div className="space-y-8 animate-fade-in">
      <section className="overflow-hidden rounded-[36px] border border-slate-800/80 bg-[radial-gradient(circle_at_top_left,_rgba(16,185,129,0.18),_transparent_34%),radial-gradient(circle_at_bottom_right,_rgba(59,130,246,0.10),_transparent_28%),linear-gradient(180deg,rgba(15,23,42,0.96),rgba(5,11,22,0.98))] p-7 shadow-[0_26px_90px_rgba(3,8,20,0.48)] sm:p-9">
        <div className="flex flex-col gap-8 xl:flex-row xl:items-end xl:justify-between">
          <div className="max-w-3xl">
            <p className="text-[11px] font-semibold uppercase tracking-[0.34em] text-brand-300">Organization Hub</p>
            <h1 className="mt-4 text-3xl font-semibold tracking-tight text-white sm:text-[42px]">
              Professional request review with faster delivery decisions.
            </h1>
            <p className="mt-4 text-[15px] leading-7 text-slate-300">
              Review the best nearby donation first, then move into the request details only when needed.
            </p>
          </div>

          <div className="grid grid-cols-2 gap-3 sm:grid-cols-4 xl:min-w-[430px]">
            <StatTile label="Requests" value={stats.requests} tone="brand" />
            <StatTile label="Nearby" value={stats.opportunities} />
            <StatTile label="Top Match" value={stats.recommended} />
            <StatTile label={isVerified ? 'Verified' : 'Review'} value={isVerified ? 'Yes' : 'Pending'} tone={isVerified ? 'success' : 'default'} />
          </div>
        </div>
      </section>

      {!isVerified ? (
        <div className="glass-card rounded-[26px] border border-amber-500/20 bg-amber-500/5 p-4 text-sm text-amber-100">
          Your organization is still awaiting admin verification. You can review nearby donations now, but accepting requests stays locked until approval.
        </div>
      ) : null}

      <div className="space-y-8">
        <section className="space-y-5">
          <div>
            <h2 className="text-[28px] font-semibold tracking-tight text-white">Accepted Requests</h2>
            <p className="mt-1 text-sm text-slate-400">Review any accepted request to continue delivery coordination and final tracking.</p>
          </div>

          <div className="space-y-4">
            {myItems.length > 0 ? myItems.map((item) => (
              <ActiveRequestCard
                key={item.id}
                item={item}
                onOpen={(id) => navigate(`/dashboard/requests/${id}`)}
              />
            )) : (
              <div className="glass-card rounded-[28px] p-10 text-center">
                <p className="text-lg font-medium text-white">No accepted requests yet</p>
                <p className="mt-2 text-sm text-slate-400">Accept one from the nearby opportunities list to move it into your request queue.</p>
              </div>
            )}
          </div>
        </section>

        <section className="space-y-5">
          <div>
            <h2 className="text-[28px] font-semibold tracking-tight text-white">Nearest Food Opportunities</h2>
            <p className="mt-1 text-sm text-slate-400">Sorted by best fit first, then nearest distance, then urgency.</p>
          </div>

          <div className="space-y-4">
            {sortedAvailable.length > 0 ? sortedAvailable.map((item, index) => (
              <OpportunityCard
                key={item.id}
                item={item}
                orgLocation={orgLocation}
                onAccept={(id) => setDialog({
                  type: 'accept',
                  id,
                  title: 'Accept Donation',
                  message: 'Accept this donation and move it into your active request queue.',
                  confirmLabel: 'Accept Donation',
                })}
                onReject={(id) => setDialog({
                  type: 'reject',
                  id,
                  title: 'Reject Donation',
                  message: 'Reject this donation only for your organization. It will still stay available for others.',
                  confirmLabel: 'Reject Donation',
                  tone: 'danger',
                })}
                disabled={!isVerified}
                order={index + 1}
              />
            )) : (
              <div className="glass-card rounded-[28px] p-10 text-center">
                <p className="text-lg font-medium text-white">No nearby donations right now</p>
                <p className="mt-2 text-sm text-slate-400">Fresh opportunities will appear here as donors post new food.</p>
              </div>
            )}
          </div>
        </section>
      </div>

      <ConfirmModal
        open={Boolean(dialog)}
        title={dialog?.title}
        message={dialog?.message}
        confirmLabel={dialog?.confirmLabel}
        tone={dialog?.tone}
        busy={actionBusy}
        onConfirm={handleConfirmDialog}
        onClose={closeDialog}
      />
    </div>
  );
}
